// Structured JSONL performance logging used by the windowed browser UI.
//
// Kept outside the `browser_ui` feature gate so unit tests can validate schema emission without
// compiling the full winit/wgpu/egui stack.
#[cfg(any(test, feature = "browser_ui"))]
use fastrender::perf_log as perf_log;

#[cfg(any(test, feature = "browser_ui"))]
fn parse_resize_dpr_scale_env(raw: Option<&str>) -> Result<f32, String> {
  // Defaults tuned for interactive resize. Lowering DPR reduces the pixmap + upload size so the UI
  // can stay responsive during a resize drag.
  const DEFAULT: f32 = 0.5;
  const MIN: f32 = 0.25;
  const MAX: f32 = 1.0;

  let Some(raw) = raw else {
    return Ok(DEFAULT);
  };
  let raw = raw.trim();
  if raw.is_empty() {
    return Ok(DEFAULT);
  }

  let parsed = raw
    .parse::<f32>()
    .map_err(|_| format!("invalid value {raw:?}; expected a finite f32"))?;
  if !parsed.is_finite() {
    return Err(format!("invalid value {raw:?}; expected a finite f32"));
  }

  Ok(parsed.clamp(MIN, MAX))
}

