#[cfg(any(test, feature = "browser_ui"))]
const RESIZE_BURST_TTL: std::time::Duration = std::time::Duration::from_millis(120);

#[cfg(any(test, feature = "browser_ui"))]
fn is_resize_burst_active(
  last_resize_event_at: Option<std::time::Instant>,
  now: std::time::Instant,
) -> bool {
  last_resize_event_at.is_some_and(|t| {
    now
      .checked_duration_since(t)
      .is_some_and(|dt| dt < RESIZE_BURST_TTL)
  })
}

#[cfg(any(test, feature = "browser_ui"))]
fn resize_burst_deadline(
  last_resize_event_at: Option<std::time::Instant>,
) -> Option<std::time::Instant> {
  last_resize_event_at.and_then(|t| t.checked_add(RESIZE_BURST_TTL))
}

#[cfg(any(test, feature = "browser_ui"))]
fn apply_global_value<T: Clone + PartialEq>(
  global: &T,
  proposed_global: Option<T>,
  windows: &[T],
) -> (T, Vec<bool>) {
  let new_global = proposed_global.unwrap_or_else(|| global.clone());
  let updates = windows
    .iter()
    .map(|value| value != &new_global)
    .collect::<Vec<_>>();
  (new_global, updates)
}

#[cfg(any(test, feature = "browser_ui"))]
fn apply_global_appearance(
  global: &fastrender::ui::appearance::AppearanceSettings,
  proposed_global: Option<fastrender::ui::appearance::AppearanceSettings>,
  windows: &[fastrender::ui::appearance::AppearanceSettings],
) -> (fastrender::ui::appearance::AppearanceSettings, Vec<bool>) {
  let proposed_global = proposed_global.map(|appearance| appearance.sanitized());
  apply_global_value(global, proposed_global, windows)
}

#[cfg(any(test, feature = "browser_ui"))]
fn normalize_home_url(raw: &str) -> Option<String> {
  let trimmed = raw.trim();
  if trimmed.is_empty() {
    return None;
  }
  if fastrender::ui::validate_user_navigation_url_scheme(trimmed).is_err() {
    return None;
  }
  Some(trimmed.to_string())
}

#[cfg(any(test, feature = "browser_ui"))]
fn apply_global_home_url(
  global: &String,
  proposed_global: Option<String>,
  windows: &[String],
) -> (String, Vec<bool>) {
  let default_home_url = fastrender::ui::about_pages::ABOUT_NEWTAB.to_string();
  let global_norm = normalize_home_url(global).unwrap_or_else(|| default_home_url.clone());
  // Only accept a proposed change if it's valid. Invalid proposals are ignored and the proposing
  // window will be corrected back to the global value.
  let proposed_norm = proposed_global.and_then(|url| normalize_home_url(&url));

  let new_global = proposed_norm.unwrap_or_else(|| global_norm.clone());
  let updates = windows.iter().map(|value| value != &new_global).collect();
  (new_global, updates)
}

#[cfg(test)]
mod input_focus_helpers_tests {
  use super::{should_forward_paste_events_to_page, should_open_page_context_menu_from_keyboard};

  #[test]
  fn keyboard_context_menu_requires_page_focus_and_no_chrome_text_focus() {
    assert!(!should_open_page_context_menu_from_keyboard(
      false, false, false
    ));
    assert!(!should_open_page_context_menu_from_keyboard(
      true, true, false
    ));
    assert!(!should_open_page_context_menu_from_keyboard(
      true, false, true
    ));
    assert!(should_open_page_context_menu_from_keyboard(
      true, false, false
    ));
  }

  #[test]
  fn paste_events_forwarding_respects_focus_and_suppression() {
    assert!(!should_forward_paste_events_to_page(false, false, false));
    assert!(!should_forward_paste_events_to_page(true, true, false));
    assert!(!should_forward_paste_events_to_page(true, false, true));
    assert!(should_forward_paste_events_to_page(true, false, false));
  }
}

#[cfg(test)]
mod global_session_settings_tests {
  use super::{apply_global_appearance, apply_global_home_url};
  use fastrender::ui::appearance::AppearanceSettings;
  use fastrender::ui::theme_parsing::BrowserTheme;

  #[test]
  fn appearance_change_updates_global_and_other_windows() {
    let global = AppearanceSettings::default();
    let mut changed = global.clone();
    changed.theme = BrowserTheme::Dark;

    let windows = vec![global.clone(), changed.clone()];
    let (new_global, updates) = apply_global_appearance(&global, Some(changed.clone()), &windows);

    assert_eq!(new_global, changed.sanitized());
    assert_eq!(updates, vec![true, false]);
  }

  #[test]
  fn appearance_is_applied_to_new_windows_without_overwriting_global() {
    let mut global = AppearanceSettings::default();
    global.ui_scale = 1.5;

    let stale_new_window = AppearanceSettings::default();
    let windows = vec![global.clone(), stale_new_window];
    let (new_global, updates) = apply_global_appearance(&global, None, &windows);

    assert_eq!(new_global, global.sanitized());
    assert_eq!(updates, vec![false, true]);
  }

  #[test]
  fn home_url_change_updates_global_and_other_windows() {
    let global = "about:newtab".to_string();
    let changed = "https://example.com".to_string();

    let windows = vec![global.clone(), changed.clone()];
    let (new_global, updates) = apply_global_home_url(&global, Some(changed.clone()), &windows);

    assert_eq!(new_global, changed);
    assert_eq!(updates, vec![true, false]);
  }

  #[test]
  fn home_url_is_applied_to_new_windows_without_overwriting_global() {
    let global = "https://example.com".to_string();
    let stale_new_window = "about:newtab".to_string();

    let windows = vec![global.clone(), stale_new_window];
    let (new_global, updates) = apply_global_home_url(&global, None, &windows);

    assert_eq!(new_global, global);
    assert_eq!(updates, vec![false, true]);
  }

  #[test]
  fn home_url_is_trimmed_and_validated() {
    let global = "about:newtab".to_string();
    let proposed = "  https://example.com/  ".to_string();

    let windows = vec![global.clone(), proposed.clone()];
    let (new_global, updates) = apply_global_home_url(&global, Some(proposed), &windows);

    assert_eq!(new_global, "https://example.com/".to_string());
    // Both windows should converge to the trimmed URL.
    assert_eq!(updates, vec![true, true]);
  }

  #[test]
  fn invalid_home_url_does_not_overwrite_valid_global() {
    let global = "https://example.com".to_string();
    let proposed = "javascript:alert(1)".to_string();

    let windows = vec![global.clone(), proposed.clone()];
    let (new_global, updates) = apply_global_home_url(&global, Some(proposed), &windows);

    assert_eq!(new_global, global);
    assert_eq!(updates, vec![false, true]);
  }
}

#[cfg(test)]
mod profile_autosave_flush_tracker_tests {
  use super::{
    ProfileAutosaveFlushFailure, ProfileAutosaveFlushTracker, PROFILE_AUTOSAVE_FLUSH_TIMEOUT,
  };
  use std::sync::mpsc;
  use std::time::{Duration, Instant};

  #[test]
  fn flush_ack_completes_and_clears_pending() {
    let (tx, rx) = mpsc::channel::<fastrender::ui::AutosaveMsg>();
    let mut tracker = ProfileAutosaveFlushTracker::new(PROFILE_AUTOSAVE_FLUSH_TIMEOUT);
    let now = Instant::now();

    assert_eq!(tracker.request_flush(Some(&tx), now), None);

    let ack_tx = match rx.recv().expect("expected flush message") {
      fastrender::ui::AutosaveMsg::Flush(ack_tx) => ack_tx,
      other => panic!("unexpected message: {other:?}"),
    };
    ack_tx.send(()).expect("ack send should succeed");

    assert_eq!(tracker.poll(Some(&tx), now), None);
    assert!(tracker.next_deadline().is_none());
  }

  #[test]
  fn flush_requests_are_coalesced_into_single_follow_up() {
    let (tx, rx) = mpsc::channel::<fastrender::ui::AutosaveMsg>();
    let mut tracker = ProfileAutosaveFlushTracker::new(PROFILE_AUTOSAVE_FLUSH_TIMEOUT);
    let now = Instant::now();

    assert_eq!(tracker.request_flush(Some(&tx), now), None);
    assert_eq!(tracker.request_flush(Some(&tx), now), None);

    let ack_tx_first = match rx.recv().expect("expected first flush") {
      fastrender::ui::AutosaveMsg::Flush(ack_tx) => ack_tx,
      other => panic!("unexpected message: {other:?}"),
    };
    assert!(rx.try_recv().is_err(), "expected no second flush yet");

    ack_tx_first.send(()).unwrap();
    assert_eq!(tracker.poll(Some(&tx), now), None);

    let ack_tx_second = match rx.recv().expect("expected follow-up flush") {
      fastrender::ui::AutosaveMsg::Flush(ack_tx) => ack_tx,
      other => panic!("unexpected message: {other:?}"),
    };
    ack_tx_second.send(()).unwrap();
    assert_eq!(tracker.poll(Some(&tx), now), None);
    assert!(tracker.next_deadline().is_none());
  }

  #[test]
  fn flush_timeout_reports_failure_and_clears_pending() {
    let (tx, rx) = mpsc::channel::<fastrender::ui::AutosaveMsg>();
    let mut tracker = ProfileAutosaveFlushTracker::new(Duration::from_millis(50));
    let now = Instant::now();

    assert_eq!(tracker.request_flush(Some(&tx), now), None);
    let _ack_tx = match rx.recv().expect("expected flush message") {
      fastrender::ui::AutosaveMsg::Flush(ack_tx) => ack_tx,
      other => panic!("unexpected message: {other:?}"),
    };

    let later = now + Duration::from_millis(60);
    assert_eq!(
      tracker.poll(Some(&tx), later),
      Some(ProfileAutosaveFlushFailure::Timeout)
    );
    assert!(tracker.next_deadline().is_none());
  }

  #[test]
  fn flush_disconnect_reports_failure() {
    let (tx, rx) = mpsc::channel::<fastrender::ui::AutosaveMsg>();
    let mut tracker = ProfileAutosaveFlushTracker::new(PROFILE_AUTOSAVE_FLUSH_TIMEOUT);
    let now = Instant::now();

    assert_eq!(tracker.request_flush(Some(&tx), now), None);
    match rx.recv().expect("expected flush message") {
      fastrender::ui::AutosaveMsg::Flush(_ack_tx) => {
        // Drop without acknowledging.
      }
      other => panic!("unexpected message: {other:?}"),
    };

    assert_eq!(
      tracker.poll(Some(&tx), now),
      Some(ProfileAutosaveFlushFailure::Disconnected)
    );
    assert!(tracker.next_deadline().is_none());
  }
}

