#[cfg(test)]
mod resize_dpr_scale_env_tests {
  use super::parse_resize_dpr_scale_env;

  #[test]
  fn parse_resize_dpr_scale_defaults_and_clamps() {
    assert!((parse_resize_dpr_scale_env(None).unwrap() - 0.5).abs() < f32::EPSILON);
    assert!((parse_resize_dpr_scale_env(Some("")).unwrap() - 0.5).abs() < f32::EPSILON);
    assert!((parse_resize_dpr_scale_env(Some("   ")).unwrap() - 0.5).abs() < f32::EPSILON);

    assert!((parse_resize_dpr_scale_env(Some("1.0")).unwrap() - 1.0).abs() < f32::EPSILON);
    assert!((parse_resize_dpr_scale_env(Some("2.0")).unwrap() - 1.0).abs() < f32::EPSILON);
    assert!((parse_resize_dpr_scale_env(Some("0.25")).unwrap() - 0.25).abs() < f32::EPSILON);
    assert!((parse_resize_dpr_scale_env(Some("0.1")).unwrap() - 0.25).abs() < f32::EPSILON);
    assert!((parse_resize_dpr_scale_env(Some("0.7")).unwrap() - 0.7).abs() < f32::EPSILON);

    assert!(parse_resize_dpr_scale_env(Some("nope")).is_err());
    assert!(parse_resize_dpr_scale_env(Some("NaN")).is_err());
    assert!(parse_resize_dpr_scale_env(Some("inf")).is_err());
  }
}

#[cfg(test)]
mod download_dir_validation_tests {
  use super::{apply_download_dir_change_state, is_path_within_any_dir, is_path_within_dir};
  use std::path::PathBuf;

  #[test]
  fn path_within_download_dir_rejects_traversal_and_outside_paths() {
    let temp = tempfile::tempdir().expect("create temp dir");
    let download_dir = temp.path().join("downloads");
    std::fs::create_dir_all(&download_dir).expect("create downloads dir");

    let valid_child = download_dir.join("file.bin");
    assert!(is_path_within_dir(&download_dir, &valid_child));

    // `..` should not be able to escape the download dir.
    let escape = download_dir.join("../escape.bin");
    assert!(!is_path_within_dir(&download_dir, &escape));

    // Absolute path outside the download dir should be rejected.
    let outside_abs = temp.path().join("outside.bin");
    assert!(!is_path_within_dir(&download_dir, &outside_abs));
  }

  #[test]
  fn apply_download_dir_change_updates_allowlist_and_allows_old_downloads() {
    let mut download_dir = PathBuf::from("downloads-a");
    let mut allowed = vec![download_dir.clone()];

    assert!(apply_download_dir_change_state(
      &mut download_dir,
      &mut allowed,
      PathBuf::from("downloads-b")
    ));
    assert_eq!(download_dir, PathBuf::from("downloads-b"));
    assert!(allowed.contains(&PathBuf::from("downloads-a")));
    assert!(allowed.contains(&PathBuf::from("downloads-b")));

    // "Open/reveal" should continue to allow paths from the previous dir.
    assert!(is_path_within_any_dir(
      &allowed,
      &PathBuf::from("downloads-a/file.bin")
    ));
  }

  #[test]
  fn apply_download_dir_change_ignores_empty_or_unchanged_values() {
    let mut download_dir = PathBuf::from("downloads-a");
    let mut allowed = vec![download_dir.clone()];

    assert!(!apply_download_dir_change_state(
      &mut download_dir,
      &mut allowed,
      PathBuf::new()
    ));
    assert_eq!(download_dir, PathBuf::from("downloads-a"));

    assert!(!apply_download_dir_change_state(
      &mut download_dir,
      &mut allowed,
      PathBuf::from("downloads-a")
    ));
    assert_eq!(download_dir, PathBuf::from("downloads-a"));
  }

  #[test]
  fn download_started_filename_is_sanitized_and_truncated_for_display() {
    use fastrender::ui::protocol_limits::MAX_DOWNLOAD_FILE_NAME_BYTES;
    use fastrender::ui::{BrowserAppState, DownloadId, TabId, WorkerToUi};

    let mut app = BrowserAppState::new();
    let raw = format!(
      "a/b\\\\c\u{0000}{}",
      "x".repeat(MAX_DOWNLOAD_FILE_NAME_BYTES + 32)
    );
    assert!(raw.len() > MAX_DOWNLOAD_FILE_NAME_BYTES);

    app.apply_worker_msg(WorkerToUi::DownloadStarted {
      tab_id: TabId(1),
      download_id: DownloadId(1),
      url: "https://example.com/file".to_string(),
      file_name: raw,
      path: std::path::PathBuf::from("downloads/file.bin"),
      total_bytes: None,
    });

    let entry = app
      .downloads
      .downloads
      .iter()
      .find(|d| d.download_id == DownloadId(1))
      .expect("download entry should be inserted");
    assert!(entry.file_name.len() <= MAX_DOWNLOAD_FILE_NAME_BYTES);
    assert!(entry.file_name.starts_with("abc"));
    assert!(!entry.file_name.contains('/'));
    assert!(!entry.file_name.contains('\\'));
    assert!(!entry.file_name.chars().any(|c| c.is_control()));
  }
}

#[cfg(test)]
mod browser_cli_flag_tests {
  use super::*;
  use clap::Parser;

  #[test]
  fn parses_hud_and_perf_log_flags() {
    let args = BrowserCliArgs::try_parse_from(["browser", "--hud", "--perf-log"]).unwrap();
    assert!(args.hud);
    assert!(!args.no_hud);
    assert!(args.perf_log);
    assert!(args.perf_log_out.is_none());

    let args =
      BrowserCliArgs::try_parse_from(["browser", "--no-hud", "--perf-log-out", "out.jsonl"])
        .unwrap();
    assert!(!args.hud);
    assert!(args.no_hud);
    assert!(!args.perf_log);
    assert_eq!(args.perf_log_out.as_deref(), Some(std::path::Path::new("out.jsonl")));
  }

  #[test]
  fn hud_cli_overrides_env() {
    let base = BrowserCliArgs::try_parse_from(["browser"]).unwrap();
    assert!(!base.hud);
    assert!(!base.no_hud);

    assert!(browser_hud_enabled_from_cli_or_env(base.hud, base.no_hud, Some("1")));
    assert!(!browser_hud_enabled_from_cli_or_env(base.hud, base.no_hud, None));

    let forced_on = BrowserCliArgs::try_parse_from(["browser", "--hud"]).unwrap();
    assert!(browser_hud_enabled_from_cli_or_env(
      forced_on.hud,
      forced_on.no_hud,
      Some("0")
    ));

    let forced_off = BrowserCliArgs::try_parse_from(["browser", "--no-hud"]).unwrap();
    assert!(!browser_hud_enabled_from_cli_or_env(
      forced_off.hud,
      forced_off.no_hud,
      Some("1")
    ));
  }

  #[test]
  fn perf_log_cli_overrides_env_and_out_path_enables() {
    let base = BrowserCliArgs::try_parse_from(["browser"]).unwrap();
    assert!(!base.perf_log);
    assert!(base.perf_log_out.is_none());

    let env_on = perf_log_config_from_cli_or_env(
      base.perf_log,
      base.perf_log_out.as_ref(),
      Some("1"),
      None,
    );
    assert!(env_on.enabled);
    assert!(env_on.out_path.is_none());

    let env_out = perf_log_config_from_cli_or_env(
      base.perf_log,
      base.perf_log_out.as_ref(),
      Some("1"),
      Some("target/env.jsonl"),
    );
    assert_eq!(
      env_out.out_path.as_deref(),
      Some(std::path::Path::new("target/env.jsonl"))
    );

    let forced_on = BrowserCliArgs::try_parse_from(["browser", "--perf-log"]).unwrap();
    let forced_on_config = perf_log_config_from_cli_or_env(
      forced_on.perf_log,
      forced_on.perf_log_out.as_ref(),
      Some("0"),
      Some("target/ignored.jsonl"),
    );
    assert!(forced_on_config.enabled);
    assert!(
      forced_on_config.out_path.is_none(),
      "expected --perf-log to force stdout"
    );

    let forced_file =
      BrowserCliArgs::try_parse_from(["browser", "--perf-log", "--perf-log-out", "target/run.jsonl"])
        .unwrap();
    let config = perf_log_config_from_cli_or_env(
      forced_file.perf_log,
      forced_file.perf_log_out.as_ref(),
      Some("0"),
      None,
    );
    assert!(config.enabled);
    assert_eq!(
      config.out_path.as_deref(),
      Some(std::path::Path::new("target/run.jsonl"))
    );

    let out_only =
      BrowserCliArgs::try_parse_from(["browser", "--perf-log-out", "out.jsonl"]).unwrap();
    let config =
      perf_log_config_from_cli_or_env(out_only.perf_log, out_only.perf_log_out.as_ref(), None, None);
    assert!(config.enabled);
    assert_eq!(config.out_path.as_deref(), Some(std::path::Path::new("out.jsonl")));
  }

  #[test]
  fn hud_flags_last_one_wins() {
    let args = BrowserCliArgs::try_parse_from(["browser", "--hud", "--no-hud"]).unwrap();
    assert!(!args.hud, "expected last flag to win");
    assert!(args.no_hud);

    let args = BrowserCliArgs::try_parse_from(["browser", "--no-hud", "--hud"]).unwrap();
    assert!(args.hud);
    assert!(!args.no_hud);
  }
}

