#[cfg(test)]
mod drain_mpsc_receiver_with_budget_tests {
  use super::*;

  #[test]
  fn stops_after_max_messages_and_allows_resuming() {
    let (tx, rx) = std::sync::mpsc::channel::<usize>();
    for value in 0..10usize {
      tx.send(value).unwrap();
    }

    let mut seen = Vec::new();
    let budget = DrainBudget {
      max_messages: 4,
      max_duration: std::time::Duration::from_secs(10),
    };

    let outcome1 = drain_mpsc_receiver_with_budget(&rx, budget, |v| seen.push(v));
    assert_eq!(outcome1.drained, 4);
    assert_eq!(outcome1.stop_reason, DrainStopReason::Budget);

    let outcome2 = drain_mpsc_receiver_with_budget(&rx, budget, |v| seen.push(v));
    assert_eq!(outcome2.drained, 4);
    assert_eq!(outcome2.stop_reason, DrainStopReason::Budget);

    let outcome3 = drain_mpsc_receiver_with_budget(&rx, budget, |v| seen.push(v));
    assert_eq!(outcome3.drained, 2);
    assert_eq!(outcome3.stop_reason, DrainStopReason::Empty);

    assert_eq!(seen, (0..10).collect::<Vec<_>>());
  }

  #[test]
  fn returns_empty_when_queue_drained_but_channel_still_open() {
    let (tx, rx) = std::sync::mpsc::channel::<usize>();
    tx.send(1).unwrap();
    tx.send(2).unwrap();

    let mut count = 0usize;
    let outcome = drain_mpsc_receiver_with_budget(
      &rx,
      DrainBudget {
        max_messages: 10,
        max_duration: std::time::Duration::from_secs(10),
      },
      |_| count += 1,
    );

    assert_eq!(count, 2);
    assert_eq!(outcome.drained, 2);
    assert_eq!(outcome.stop_reason, DrainStopReason::Empty);

    // Keep `tx` alive; receiver should still report empty.
    let outcome = drain_mpsc_receiver_with_budget(
      &rx,
      DrainBudget {
        max_messages: 10,
        max_duration: std::time::Duration::from_secs(10),
      },
      |_| unreachable!(),
    );
    assert_eq!(outcome.drained, 0);
    assert_eq!(outcome.stop_reason, DrainStopReason::Empty);
  }

  #[test]
  fn returns_disconnected_when_sender_dropped_and_queue_drained() {
    let (tx, rx) = std::sync::mpsc::channel::<usize>();
    tx.send(1).unwrap();
    tx.send(2).unwrap();
    drop(tx);

    let mut collected = Vec::new();
    let outcome = drain_mpsc_receiver_with_budget(
      &rx,
      DrainBudget {
        max_messages: 10,
        max_duration: std::time::Duration::from_secs(10),
      },
      |v| collected.push(v),
    );

    assert_eq!(collected, vec![1, 2]);
    assert_eq!(outcome.drained, 2);
    assert_eq!(outcome.stop_reason, DrainStopReason::Disconnected);
  }

  #[test]
  fn respects_zero_budgets() {
    let (tx, rx) = std::sync::mpsc::channel::<usize>();
    for value in 0..3usize {
      tx.send(value).unwrap();
    }

    let mut drained = Vec::new();
    let outcome = drain_mpsc_receiver_with_budget(
      &rx,
      DrainBudget {
        max_messages: 0,
        max_duration: std::time::Duration::from_secs(10),
      },
      |v| drained.push(v),
    );
    assert_eq!(drained, Vec::<usize>::new());
    assert_eq!(outcome.drained, 0);
    assert_eq!(outcome.stop_reason, DrainStopReason::Budget);

    let outcome = drain_mpsc_receiver_with_budget(
      &rx,
      DrainBudget {
        max_messages: 10,
        max_duration: std::time::Duration::from_nanos(0),
      },
      |v| drained.push(v),
    );
    assert_eq!(outcome.drained, 0);
    assert_eq!(outcome.stop_reason, DrainStopReason::Budget);

    let outcome = drain_mpsc_receiver_with_budget(
      &rx,
      DrainBudget {
        max_messages: 10,
        max_duration: std::time::Duration::from_secs(10),
      },
      |v| drained.push(v),
    );
    assert_eq!(outcome.drained, 3);
    assert_eq!(outcome.stop_reason, DrainStopReason::Empty);
    assert_eq!(drained, vec![0, 1, 2]);
  }
}

#[cfg(test)]
mod protocol_payload_sanitization_tests {
  use super::sanitize_worker_to_ui_for_windowed_browser;
  use fastrender::geometry::Rect;
  use fastrender::tree::box_tree::{SelectControl, SelectItem};
  use fastrender::ui::messages::DateTimeInputKind;
  use fastrender::ui::protocol_limits::{
    MAX_ACCEPT_ATTR_BYTES, MAX_INPUT_VALUE_BYTES, MAX_SELECT_ITEMS, MAX_SELECT_LABEL_BYTES,
  };
  use fastrender::ui::{TabId, WorkerToUi};
  use std::sync::Arc;

  fn euro_string(bytes_over: usize) -> String {
    // "€" is 3 bytes in UTF-8; this helps ensure truncation respects char boundaries.
    let base_chars = (bytes_over / 3) + 16;
    "€".repeat(base_chars)
  }

  #[test]
  fn select_dropdown_open_with_too_many_items_is_dropped() {
    let items = (0..(MAX_SELECT_ITEMS + 1))
      .map(|idx| SelectItem::Option {
        node_id: idx + 1,
        label: format!("Item {idx}"),
        value: format!("v{idx}"),
        selected: false,
        disabled: false,
        in_optgroup: false,
      })
      .collect::<Vec<_>>();
    let control = SelectControl {
      multiple: false,
      size: 1,
      items: Arc::new(items),
      selected: Vec::new(),
    };

    let msg = WorkerToUi::SelectDropdownOpened {
      tab_id: TabId(1),
      select_node_id: 42,
      control,
      anchor_css: Rect::from_xywh(0.0, 0.0, 10.0, 10.0),
    };

    assert!(
      sanitize_worker_to_ui_for_windowed_browser(msg).is_none(),
      "expected oversized SelectDropdownOpened to be dropped"
    );
  }

  #[test]
  fn select_dropdown_item_labels_and_values_are_truncated() {
    let label = euro_string(MAX_SELECT_LABEL_BYTES + 8);
    let value = euro_string(MAX_SELECT_LABEL_BYTES + 32);
    let items = vec![SelectItem::Option {
      node_id: 1,
      label,
      value,
      selected: false,
      disabled: false,
      in_optgroup: false,
    }];
    let control = SelectControl {
      multiple: false,
      size: 1,
      items: Arc::new(items),
      selected: vec![0],
    };

    let msg = WorkerToUi::OpenSelectDropdown {
      tab_id: TabId(1),
      select_node_id: 1,
      control,
    };

    let msg = sanitize_worker_to_ui_for_windowed_browser(msg).expect("message should be kept");
    let WorkerToUi::OpenSelectDropdown { control, .. } = msg else {
      panic!("expected OpenSelectDropdown after sanitization");
    };
    assert_eq!(control.items.len(), 1);
    let SelectItem::Option { label, value, .. } = &control.items[0] else {
      panic!("expected option item");
    };
    assert!(
      label.as_bytes().len() <= MAX_SELECT_LABEL_BYTES,
      "label not truncated: {} bytes",
      label.len()
    );
    assert!(
      value.as_bytes().len() <= MAX_SELECT_LABEL_BYTES,
      "value not truncated: {} bytes",
      value.len()
    );
    // Ensure truncation didn't split the 3-byte "€" character.
    assert_eq!(label.as_bytes().len() % 3, 0);
    assert_eq!(value.as_bytes().len() % 3, 0);
  }

  #[test]
  fn date_time_picker_value_is_truncated() {
    let value = euro_string(MAX_INPUT_VALUE_BYTES + 64);
    let msg = WorkerToUi::DateTimePickerOpened {
      tab_id: TabId(1),
      input_node_id: 99,
      kind: DateTimeInputKind::DateTimeLocal,
      value,
      anchor_css: Rect::from_xywh(1.0, 2.0, 3.0, 4.0),
    };

    let msg = sanitize_worker_to_ui_for_windowed_browser(msg).expect("message should be kept");
    let WorkerToUi::DateTimePickerOpened { value, .. } = msg else {
      panic!("expected DateTimePickerOpened after sanitization");
    };
    assert!(value.as_bytes().len() <= MAX_INPUT_VALUE_BYTES);
    assert_eq!(value.as_bytes().len() % 3, 0);
  }

  #[test]
  fn file_picker_accept_is_truncated_and_anchor_css_is_sanitized() {
    let accept = Some(euro_string(MAX_ACCEPT_ATTR_BYTES + 64));
    let msg = WorkerToUi::FilePickerOpened {
      tab_id: TabId(1),
      input_node_id: 5,
      multiple: true,
      accept,
      anchor_css: Rect::from_xywh(f32::NAN, f32::INFINITY, -f32::INFINITY, f32::NAN),
    };

    let msg = sanitize_worker_to_ui_for_windowed_browser(msg).expect("message should be kept");
    let WorkerToUi::FilePickerOpened {
      accept, anchor_css, ..
    } = msg
    else {
      panic!("expected FilePickerOpened after sanitization");
    };
    let accept = accept.expect("accept should remain Some");
    assert!(accept.as_bytes().len() <= MAX_ACCEPT_ATTR_BYTES);
    assert_eq!(accept.as_bytes().len() % 3, 0);

    assert!(anchor_css.origin.x.is_finite());
    assert!(anchor_css.origin.y.is_finite());
    assert!(anchor_css.size.width.is_finite());
    assert!(anchor_css.size.height.is_finite());
    assert!(anchor_css.size.width >= 0.0);
    assert!(anchor_css.size.height >= 0.0);
    assert!(anchor_css.origin.x.abs() <= 1_000_000.0);
    assert!(anchor_css.origin.y.abs() <= 1_000_000.0);
    assert!(anchor_css.size.width <= 1_000_000.0);
    assert!(anchor_css.size.height <= 1_000_000.0);
  }
}

#[cfg(test)]
mod scroll_coalescer_tests {
  use super::ScrollCoalescer;
  use fastrender::ui::{TabId, UiToWorker};

  #[test]
  fn sums_deltas_correctly() {
    let mut coalescer = ScrollCoalescer::default();
    let tab_id = TabId(1);
    coalescer.push_scroll(tab_id, (1.0, 2.0), Some((10.0, 20.0)));
    coalescer.push_scroll(tab_id, (3.5, -1.0), Some((11.0, 21.0)));

    match coalescer.take_scroll_msg() {
      Some(UiToWorker::Scroll {
        tab_id: got_tab,
        delta_css,
        pointer_css,
      }) => {
        assert_eq!(got_tab, tab_id);
        assert_eq!(delta_css, (4.5, 1.0));
        assert_eq!(pointer_css, Some((11.0, 21.0)));
      }
      other => panic!("expected Scroll message, got {other:?}"),
    }

    assert!(coalescer.take_scroll_msg().is_none());
  }

  #[test]
  fn resets_on_tab_change() {
    let mut coalescer = ScrollCoalescer::default();
    let tab_a = TabId(1);
    let tab_b = TabId(2);
    coalescer.push_scroll(tab_a, (1.0, 1.0), Some((0.0, 0.0)));
    coalescer.push_scroll(tab_b, (2.0, 0.0), Some((5.0, 5.0)));

    match coalescer.take_scroll_msg() {
      Some(UiToWorker::Scroll {
        tab_id, delta_css, ..
      }) => {
        assert_eq!(tab_id, tab_b);
        assert_eq!(delta_css, (2.0, 0.0));
      }
      other => panic!("expected Scroll message, got {other:?}"),
    }
  }

  #[test]
  fn uses_latest_pointer_position() {
    let mut coalescer = ScrollCoalescer::default();
    let tab_id = TabId(7);
    coalescer.push_scroll(tab_id, (0.0, 1.0), Some((1.0, 1.0)));
    coalescer.push_scroll(tab_id, (0.0, 1.0), Some((9.0, 9.0)));

    match coalescer.take_scroll_msg() {
      Some(UiToWorker::Scroll { pointer_css, .. }) => {
        assert_eq!(pointer_css, Some((9.0, 9.0)));
      }
      other => panic!("expected Scroll message, got {other:?}"),
    }
  }
}

#[cfg(test)]
mod clipboard_limit_tests {
  use super::write_clipboard_update_if_within_limit;
  use fastrender::ui::protocol_limits::{
    sanitize_worker_to_ui_clipboard_message, ClipboardTextLimitResult, MAX_CLIPBOARD_TEXT_BYTES,
  };
  use fastrender::ui::{TabId, WorkerToUi};

  #[test]
  fn oversized_worker_clipboard_payload_is_dropped() {
    let oversized = "a".repeat(MAX_CLIPBOARD_TEXT_BYTES + 1);
    let msg = WorkerToUi::SetClipboardText {
      tab_id: TabId(1),
      text: oversized,
    };
    let (_msg, update) = sanitize_worker_to_ui_clipboard_message(msg);
    let update = update.expect("expected clipboard update");
    assert!(update.truncated);

    let mut called = false;
    let wrote = write_clipboard_update_if_within_limit(&update, |_text| called = true);
    assert!(!wrote);
    assert!(!called);
  }

  #[test]
  fn in_limit_worker_clipboard_payload_is_forwarded() {
    let msg = WorkerToUi::SetClipboardText {
      tab_id: TabId(1),
      text: "ok".to_string(),
    };
    let (_msg, update) = sanitize_worker_to_ui_clipboard_message(msg);
    let update = update.expect("expected clipboard update");
    assert!(!update.truncated);

    let mut called = false;
    let wrote = write_clipboard_update_if_within_limit(&update, |text| {
      assert_eq!(text, "ok");
      called = true;
    });
    assert!(wrote);
    assert!(called);
  }

  #[test]
  fn defense_in_depth_rejects_payloads_that_still_exceed_limit() {
    let update = ClipboardTextLimitResult {
      tab_id: TabId(1),
      text: "a".repeat(MAX_CLIPBOARD_TEXT_BYTES + 1),
      truncated: false,
      original_bytes: MAX_CLIPBOARD_TEXT_BYTES + 1,
    };

    let mut called = false;
    let wrote = write_clipboard_update_if_within_limit(&update, |_text| called = true);
    assert!(!wrote);
    assert!(!called);
  }
}

#[cfg(test)]
mod clipboard_write_gate_integration_tests {
  use super::write_clipboard_update_if_within_limit;
  use fastrender::ui::clipboard_gate::{ClipboardWriteGate, ClipboardWriteGateDecision};
  use fastrender::ui::protocol_limits::sanitize_worker_to_ui_clipboard_message;
  use fastrender::ui::{TabId, WorkerToUi};

  #[test]
  fn unsolicited_clipboard_write_is_not_forwarded_to_os_clipboard() {
    let tab_id = TabId(1);
    let msg = WorkerToUi::SetClipboardText {
      tab_id,
      text: "ok".to_string(),
    };
    let (_msg, update) = sanitize_worker_to_ui_clipboard_message(msg);
    let update = update.expect("expected clipboard update");

    let mut gate = ClipboardWriteGate::new();
    let mut called = false;
    let mut wrote = false;

    match gate.on_worker_set_clipboard_text(update.tab_id) {
      ClipboardWriteGateDecision::Allowed => {
        wrote = write_clipboard_update_if_within_limit(&update, |_text| called = true);
      }
      ClipboardWriteGateDecision::Rejected { .. } => {}
    }

    assert!(!wrote, "unexpected clipboard write should not be forwarded");
    assert!(
      !called,
      "unsolicited SetClipboardText must not attempt to write to the OS clipboard"
    );
  }

  #[test]
  fn clipboard_write_after_copy_is_forwarded_once() {
    let tab_id = TabId(7);
    let msg = WorkerToUi::SetClipboardText {
      tab_id,
      text: "hello".to_string(),
    };
    let (_msg, update) = sanitize_worker_to_ui_clipboard_message(msg);
    let update = update.expect("expected clipboard update");

    let mut gate = ClipboardWriteGate::new();
    gate.register_copy(tab_id);

    let mut called = false;
    match gate.on_worker_set_clipboard_text(update.tab_id) {
      ClipboardWriteGateDecision::Allowed => {
        assert!(write_clipboard_update_if_within_limit(&update, |text| {
          assert_eq!(text, "hello");
          called = true;
        }));
      }
      ClipboardWriteGateDecision::Rejected { .. } => {
        panic!("expected clipboard write to be allowed")
      }
    }
    assert!(called);

    // Arm is one-shot: further writes should be rejected.
    assert!(matches!(
      gate.on_worker_set_clipboard_text(update.tab_id),
      ClipboardWriteGateDecision::Rejected { .. }
    ));
  }
}

#[cfg(test)]
mod wheel_delta_shift_mapping_tests {
  use super::remap_wheel_delta_for_shift;

  #[test]
  fn shift_wheel_maps_vertical_delta_to_horizontal() {
    assert_eq!(remap_wheel_delta_for_shift((0.0, 5.0), false), (0.0, 5.0));
    assert_eq!(remap_wheel_delta_for_shift((0.0, 5.0), true), (5.0, 0.0));
  }

  #[test]
  fn shift_wheel_preserves_existing_horizontal_delta() {
    assert_eq!(remap_wheel_delta_for_shift((3.0, 0.0), true), (3.0, 0.0));
    assert_eq!(remap_wheel_delta_for_shift((3.0, 7.0), true), (3.0, 7.0));
    // If the delta is primarily horizontal already, leave it unchanged.
    assert_eq!(remap_wheel_delta_for_shift((7.0, 3.0), true), (7.0, 3.0));
  }
}

#[cfg(test)]
mod profile_update_redraw_tests {
  use super::*;

  fn state<'a>(
    bookmarks: &'a fastrender::ui::BookmarkStore,
    active_tab_url: Option<&'a str>,
  ) -> ProfileUpdateRedrawState<'a> {
    ProfileUpdateRedrawState {
      bookmarks_panel_open: false,
      history_panel_open: false,
      bookmarks_bar_visible: false,
      omnibox_open: false,
      active_tab_url,
      bookmarks,
    }
  }

  #[test]
  fn bookmarks_update_redraws_for_visible_bookmarks_ui() {
    let old_store = fastrender::ui::BookmarkStore::default();
    let new_store = fastrender::ui::BookmarkStore::default();

    assert!(needs_redraw_for_profile_update_state(
      ProfileUpdateKind::Bookmarks {
        new_bookmarks: &new_store,
      },
      ProfileUpdateRedrawState {
        bookmarks_panel_open: true,
        ..state(&old_store, None)
      }
    ));

    assert!(needs_redraw_for_profile_update_state(
      ProfileUpdateKind::Bookmarks {
        new_bookmarks: &new_store,
      },
      ProfileUpdateRedrawState {
        bookmarks_bar_visible: true,
        ..state(&old_store, None)
      }
    ));

    assert!(needs_redraw_for_profile_update_state(
      ProfileUpdateKind::Bookmarks {
        new_bookmarks: &new_store,
      },
      ProfileUpdateRedrawState {
        omnibox_open: true,
        ..state(&old_store, None)
      }
    ));

    assert!(needs_redraw_for_profile_update_state(
      ProfileUpdateKind::Bookmarks {
        new_bookmarks: &new_store,
      },
      state(&old_store, Some("about:newtab"))
    ));

    assert!(needs_redraw_for_profile_update_state(
      ProfileUpdateKind::Bookmarks {
        new_bookmarks: &new_store,
      },
      state(&old_store, Some("about:bookmarks"))
    ));
  }

  #[test]
  fn bookmarks_update_redraws_when_active_tab_bookmark_star_changes() {
    let old_store = fastrender::ui::BookmarkStore::default();
    let mut new_store = fastrender::ui::BookmarkStore::default();
    new_store.toggle("https://example.com/", None);

    assert!(needs_redraw_for_profile_update_state(
      ProfileUpdateKind::Bookmarks {
        new_bookmarks: &new_store,
      },
      state(&old_store, Some("https://example.com/"))
    ));

    assert!(
      !needs_redraw_for_profile_update_state(
        ProfileUpdateKind::Bookmarks {
          new_bookmarks: &new_store,
        },
        state(&old_store, Some("https://other.example/"))
      ),
      "unrelated URL should not trigger bookmark-star redraw"
    );
  }

  #[test]
  fn history_update_redraws_only_when_history_ui_is_visible() {
    let bookmarks = fastrender::ui::BookmarkStore::default();
    let history = fastrender::ui::GlobalHistoryStore::default();

    assert!(needs_redraw_for_profile_update_state(
      ProfileUpdateKind::History {
        new_history: &history,
      },
      ProfileUpdateRedrawState {
        history_panel_open: true,
        ..state(&bookmarks, None)
      }
    ));

    assert!(needs_redraw_for_profile_update_state(
      ProfileUpdateKind::History {
        new_history: &history,
      },
      ProfileUpdateRedrawState {
        omnibox_open: true,
        ..state(&bookmarks, None)
      }
    ));

    assert!(needs_redraw_for_profile_update_state(
      ProfileUpdateKind::History {
        new_history: &history,
      },
      state(&bookmarks, Some("about:newtab"))
    ));

    assert!(needs_redraw_for_profile_update_state(
      ProfileUpdateKind::History {
        new_history: &history,
      },
      state(&bookmarks, Some("about:history?q=rust"))
    ));

    assert!(
      !needs_redraw_for_profile_update_state(
        ProfileUpdateKind::History {
          new_history: &history,
        },
        state(&bookmarks, Some("about:bookmarks"))
      ),
      "about:bookmarks should not require redraw for history updates"
    );
  }
}

