#[cfg(feature = "browser_ui")]
#[derive(Debug)]
enum UserEvent {
  WorkerWake,
  /// Clear completed downloads from the profile-global downloads store.
  ClearCompletedDownloads,
  SearchSuggestWake(winit::window::WindowId),
  RequestNewWindow(winit::window::WindowId),
  RequestNewWindowWithSession {
    from_id: winit::window::WindowId,
    window: fastrender::ui::BrowserSessionWindow,
  },
  /// Discard the currently restored session and start fresh (single clean `about:newtab` window).
  StartNewSession(winit::window::WindowId),
  /// Request showing a transient chrome toast on a specific window.
  ///
  /// This is primarily used by background helper threads (native dialogs) which cannot directly
  /// mutate the `App` state.
  ShowChromeToast {
    window_id: winit::window::WindowId,
    kind: fastrender::ui::ToastKind,
    text: String,
  },
  FilePickerNativeDialogFallback {
    window_id: winit::window::WindowId,
    tab_id: fastrender::ui::TabId,
    input_node_id: usize,
    multiple: bool,
    accept: Option<String>,
    anchor_css: fastrender::geometry::Rect,
    anchor_points: egui::Pos2,
  },
  PageExportNativeDialogFallback {
    window_id: winit::window::WindowId,
    tab_id: fastrender::ui::TabId,
    kind: PageExportKind,
    suggested_name: String,
    default_dir: std::path::PathBuf,
  },
  PageExportNativeDialogChosen {
    window_id: winit::window::WindowId,
    tab_id: fastrender::ui::TabId,
    kind: PageExportKind,
    path: std::path::PathBuf,
  },
  PageExportFinished {
    window_id: winit::window::WindowId,
    kind: PageExportKind,
    result: Result<std::path::PathBuf, String>,
  },
  /// An accessibility action request (e.g. "activate" or "focus") dispatched by the OS via AccessKit.
  AccessKitAction {
    window_id: winit::window::WindowId,
    request: accesskit::ActionRequest,
  },
}

#[cfg(feature = "browser_ui")]
impl From<accesskit_winit::ActionRequestEvent> for UserEvent {
  fn from(event: accesskit_winit::ActionRequestEvent) -> Self {
    UserEvent::AccessKitAction {
      window_id: event.window_id,
      request: event.request,
    }
  }
}

#[cfg(any(test, feature = "browser_ui"))]
#[derive(clap::Parser, Debug)]
#[command(
  name = "browser",
  about = "FastRender browser UI (experimental)",
  disable_version_flag = true,
  disable_help_subcommand = true,
  color = clap::ColorChoice::Never,
  term_width = 90,
  after_help = "If URL is omitted, the browser attempts to restore the previous session; if none exists it opens `about:newtab`.\nUse `--restore` to try restoring even when a URL is provided, or `--no-restore` to disable session restore.\nUse `--session-path` (or `FASTR_BROWSER_SESSION_PATH`) to run multiple isolated instances.\nThe URL value is resolved like the address bar: URL-like inputs are normalized (e.g. `example.com` → https), otherwise treated as a DuckDuckGo search (e.g. `cats` → https://duckduckgo.com/?q=cats).\nSupported schemes: http, https, file, about."
)]
struct BrowserCliArgs {
  /// Start URL (omit to restore previous session when available; otherwise `about:newtab`)
  #[arg(value_name = "URL")]
  url: Option<String>,

  /// Try to restore the previous session (even when a URL is provided)
  #[arg(long, action = clap::ArgAction::SetTrue, overrides_with = "no_restore")]
  restore: bool,

  /// Do not restore the previous session
  #[arg(long = "no-restore", action = clap::ArgAction::SetTrue, overrides_with = "restore")]
  no_restore: bool,

  /// Override the browser session file location (and corresponding lock file)
  ///
  /// When unset, defaults to `FASTR_BROWSER_SESSION_PATH`, then a per-user config directory.
  #[arg(long = "session-path", value_name = "PATH")]
  session_path: Option<std::path::PathBuf>,

  /// Override the address-space memory limit in MiB (0 disables)
  ///
  /// When unset, defaults to the `FASTR_BROWSER_MEM_LIMIT_MB` environment variable.
  #[arg(long = "mem-limit-mb", value_name = "MB", value_parser = parse_u64_mb)]
  mem_limit_mb: Option<u64>,

  /// Directory to save downloaded files
  ///
  /// When unset, defaults to `FASTR_BROWSER_DOWNLOAD_DIR`, then to the OS downloads directory, then
  /// to the current working directory.
  #[arg(long = "download-dir", value_name = "PATH")]
  download_dir: Option<std::path::PathBuf>,

  /// Show an in-app HUD overlay with browser/debug metrics
  ///
  /// CLI overrides `FASTR_BROWSER_HUD`. When neither the flag nor env var is set, the HUD is off.
  #[arg(long, action = clap::ArgAction::SetTrue, overrides_with = "no_hud")]
  hud: bool,

  /// Do not show the in-app HUD overlay
  ///
  /// CLI overrides `FASTR_BROWSER_HUD`. When neither the flag nor env var is set, the HUD is off.
  #[arg(long = "no-hud", action = clap::ArgAction::SetTrue, overrides_with = "hud")]
  no_hud: bool,

  /// Emit a machine-readable performance log (JSONL) to stdout
  ///
  /// CLI overrides `FASTR_PERF_LOG` (and forces stdout even if `FASTR_PERF_LOG_OUT` is set).
  /// When neither the flag nor env var is set, perf logging is off.
  #[arg(long = "perf-log", action = clap::ArgAction::SetTrue)]
  perf_log: bool,

  /// Write the performance log (JSONL) to a file instead of stdout
  ///
  /// When set, perf logging is enabled regardless of `FASTR_PERF_LOG`, and the output path
  /// overrides `FASTR_PERF_LOG_OUT`.
  #[arg(long = "perf-log-out", value_name = "PATH")]
  perf_log_out: Option<std::path::PathBuf>,

  /// wgpu adapter power preference when selecting a GPU
  ///
  /// - `high`: prefer a discrete/high-performance GPU (default)
  /// - `low`: prefer an integrated/low-power GPU
  /// - `none`: no preference (wgpu default behaviour)
  #[arg(
    long = "power-preference",
    value_enum,
    default_value_t = CliPowerPreference::High,
    value_name = "PREF"
  )]
  power_preference: CliPowerPreference,

  /// Force a fallback adapter (e.g. software rasterizer) during wgpu adapter selection.
  ///
  /// Equivalent env: `FASTR_BROWSER_WGPU_FALLBACK=1`.
  #[arg(
    long = "force-fallback-adapter",
    alias = "wgpu-fallback",
    action = clap::ArgAction::SetTrue
  )]
  force_fallback_adapter: bool,

  /// Restrict the wgpu backend set used for instance/adapter creation (comma-separated)
  ///
  /// Examples:
  ///   --wgpu-backends all
  ///   --wgpu-backends vulkan
  ///   --wgpu-backends vulkan,gl
  ///
  /// Equivalent env: `FASTR_BROWSER_WGPU_BACKENDS=...`.
  #[arg(
    long = "wgpu-backends",
    alias = "wgpu-backend",
    value_delimiter = ',',
    value_enum,
    value_name = "BACKEND"
  )]
  wgpu_backends: Option<Vec<CliWgpuBackend>>,

  /// Enable the renderer watchdog (unresponsive/crash-smoke timeout).
  ///
  /// When unset, defaults to `FASTR_BROWSER_RENDERER_WATCHDOG`.
  #[arg(
    long = "renderer-watchdog",
    action = clap::ArgAction::SetTrue,
    overrides_with = "no_renderer_watchdog"
  )]
  renderer_watchdog: bool,

  /// Disable the renderer watchdog.
  ///
  /// When unset, defaults to `FASTR_BROWSER_RENDERER_WATCHDOG`.
  #[arg(
    long = "no-renderer-watchdog",
    action = clap::ArgAction::SetTrue,
    overrides_with = "renderer_watchdog"
  )]
  no_renderer_watchdog: bool,

  /// Renderer watchdog timeout in milliseconds.
  ///
  /// When unset, defaults to `FASTR_BROWSER_RENDERER_WATCHDOG_TIMEOUT_MS`.
  #[arg(
    long = "renderer-watchdog-timeout-ms",
    alias = "renderer-watchdog-ms",
    value_name = "MS",
    value_parser = parse_u64_ms
  )]
  renderer_watchdog_timeout_ms: Option<u64>,

  /// Allow navigating to `crash://` URLs (testing hook).
  ///
  /// Equivalent env: `FASTR_BROWSER_ALLOW_CRASH_URLS=1`.
  #[arg(long = "allow-crash-urls", action = clap::ArgAction::SetTrue)]
  allow_crash_urls: bool,

  /// Run a minimal headless startup smoke test (no window / wgpu init)
  #[arg(long = "headless-smoke", action = clap::ArgAction::SetTrue)]
  headless_smoke: bool,

  /// Run a minimal headless download smoke test (no window / wgpu init).
  ///
  /// This mode is intended for CI: it navigates to the provided `file://` URL, clicks a download
  /// link, and asserts the downloaded file lands under the configured download directory.
  #[arg(long = "headless-download-smoke", action = clap::ArgAction::SetTrue)]
  headless_download_smoke: bool,

  /// Run a minimal headless crash-isolation smoke test (no window / wgpu init)
  ///
  /// This mode spawns a UI worker, opens a tab, navigates to `crash://panic`, and asserts the
  /// worker terminates while the browser process stays alive.
  #[arg(long = "headless-crash-smoke", action = clap::ArgAction::SetTrue)]
  headless_crash_smoke: bool,

  /// Enable JavaScript execution (experimental)
  ///
  /// The windowed browser UI runs author scripts using the `vm-js` engine.
  ///
  /// In `--headless-smoke` mode, this flag selects a `vm-js` `BrowserTab` smoke test.
  #[arg(long = "js", action = clap::ArgAction::SetTrue)]
  js_enabled: bool,

  /// Exit after parsing CLI + applying mem limits, without creating a window
  #[arg(long = "exit-immediately", action = clap::ArgAction::SetTrue)]
  exit_immediately: bool,
}

