/// Plan for resetting an existing window to a fresh session (single `about:newtab` tab).
#[cfg(any(test, feature = "browser_ui"))]
#[derive(Debug)]
struct StartNewSessionPlan {
  new_tab_id: fastrender::ui::TabId,
  closed_tab_ids: Vec<fastrender::ui::TabId>,
}

#[cfg(any(test, feature = "browser_ui"))]
fn plan_start_new_session_for_window(
  app: &mut fastrender::ui::BrowserAppState,
) -> StartNewSessionPlan {
  let closed_tab_ids: Vec<fastrender::ui::TabId> = app.tabs.iter().map(|t| t.id).collect();
  let new_tab_id = app.create_tab(Some(fastrender::ui::about_pages::ABOUT_NEWTAB.to_string()));

  for tab_id in &closed_tab_ids {
    let _ = app.remove_tab(*tab_id);
    #[cfg(feature = "browser_ui")]
    {
      app.chrome.clear_tab_close(*tab_id);
    }
  }

  // Discard any "reopen closed tab" history from the restored session.
  app.closed_tabs.clear();
  // Discard restored tab groups; a new session starts with no groups.
  app.tab_groups.clear();

  StartNewSessionPlan {
    new_tab_id,
    closed_tab_ids,
  }
}

/// After starting a fresh session, collapse the window list to a single active window.
///
/// This matches typical crash-recovery UX in mainstream browsers: "start new session" should leave
/// the user with one clean window rather than resetting every restored window independently.
#[cfg(any(test, feature = "browser_ui"))]
fn collapse_windows_to_single_active<K, V, F>(
  windows: &mut std::collections::HashMap<K, V>,
  window_order: &mut Vec<K>,
  active_window_id: &mut Option<K>,
  mut on_close: F,
) where
  K: Copy + Eq + std::hash::Hash,
  F: FnMut(V),
{
  if windows.len() <= 1 {
    if windows.len() == 1 {
      let only_id = windows.keys().next().copied();
      if let Some(id) = only_id {
        window_order.clear();
        window_order.push(id);
        *active_window_id = Some(id);
      }
    }
    return;
  }

  // Determine which window to keep.
  let mut keep_id = active_window_id.filter(|id| windows.contains_key(id));
  if keep_id.is_none() {
    keep_id = window_order.iter().copied().find(|id| windows.contains_key(id));
  }
  if keep_id.is_none() {
    keep_id = windows.keys().next().copied();
  }
  let Some(keep_id) = keep_id else {
    return;
  };

  // Close every other window.
  let to_close: Vec<K> = windows.keys().copied().filter(|id| *id != keep_id).collect();
  for id in to_close {
    if let Some(win) = windows.remove(&id) {
      on_close(win);
    }
  }

  window_order.clear();
  window_order.push(keep_id);
  *active_window_id = Some(keep_id);
}

#[cfg(test)]
mod crash_recovery_prompt_tests {
  use super::*;

  #[test]
  fn crash_recovery_infobar_shows_only_for_unclean_restored_sessions() {
    assert!(!should_show_crash_recovery_infobar(
      StartupSessionSource::Restored,
      true
    ));
    assert!(should_show_crash_recovery_infobar(
      StartupSessionSource::Restored,
      false
    ));
    assert!(!should_show_crash_recovery_infobar(
      StartupSessionSource::CliUrl,
      false
    ));
    assert!(!should_show_crash_recovery_infobar(
      StartupSessionSource::DefaultNewTab,
      false
    ));
    assert!(!should_show_crash_recovery_infobar(
      StartupSessionSource::SafeMode,
      false
    ));
    assert!(!should_show_crash_recovery_infobar(
      StartupSessionSource::HeadlessOverride,
      false
    ));
  }

  #[test]
  fn crash_recovery_infobar_opens_only_in_active_window_for_multi_window_restore() {
    let show = should_show_crash_recovery_infobar(StartupSessionSource::Restored, false);
    let window_count = 2;
    let active_window_index = 1;
    let active_idx = active_window_index.min(window_count.saturating_sub(1));

    let open_states: Vec<bool> = (0..window_count)
      .map(|idx| should_open_crash_recovery_infobar_for_window(show, idx, active_idx))
      .collect();
    assert_eq!(open_states, vec![false, true]);
  }

  #[test]
  fn start_new_session_plan_resets_state_to_single_newtab_session_snapshot() {
    use fastrender::ui::{BrowserAppState, BrowserSession, BrowserTabState};

    let mut app = BrowserAppState::new();
    app.push_tab(
      BrowserTabState::new(
        fastrender::ui::TabId::new(),
        "https://example.com".to_string(),
      ),
      true,
    );
    app.push_tab(
      BrowserTabState::new(fastrender::ui::TabId::new(), "about:newtab".to_string()),
      false,
    );
    app.closed_tabs.push(fastrender::ui::ClosedTabState {
      url: "https://old.example".to_string(),
      title: None,
      pinned: false,
    });

    let plan = plan_start_new_session_for_window(&mut app);
    assert!(!plan.closed_tab_ids.is_empty());

    let session = BrowserSession::from_app_state(&app);
    assert_eq!(session.windows.len(), 1);
    assert_eq!(session.windows[0].tabs.len(), 1);
    assert_eq!(
      session.windows[0].tabs[0].url,
      fastrender::ui::about_pages::ABOUT_NEWTAB
    );
  }

  #[test]
  fn start_new_session_collapses_to_single_window_and_persists_single_window_session() {
    use fastrender::ui::session::BrowserSessionWindow;
    use fastrender::ui::{appearance::AppearanceSettings, BrowserAppState, BrowserTabState, TabId};
    use std::collections::HashMap;

    let mut win_a = BrowserAppState::new();
    win_a.push_tab(
      BrowserTabState::new(TabId::new(), "https://example.com".to_string()),
      true,
    );
    win_a.push_tab(
      BrowserTabState::new(TabId::new(), "https://example.net".to_string()),
      false,
    );

    let mut win_b = BrowserAppState::new();
    win_b.push_tab(
      BrowserTabState::new(TabId::new(), "https://b.example".to_string()),
      true,
    );
    // Ensure we can distinguish the kept window from the session module's fallback window. The
    // fallback uses `default_show_menu_bar()`, so pick the opposite.
    win_b.chrome.show_menu_bar = cfg!(target_os = "macos");

    let mut windows: HashMap<u64, BrowserAppState> = HashMap::new();
    windows.insert(1, win_a);
    windows.insert(2, win_b);
    let mut window_order = vec![1u64, 2u64];
    let mut active_window_id = Some(2u64);

    for app in windows.values_mut() {
      let _ = plan_start_new_session_for_window(app);
    }

    let mut closed = 0usize;
    collapse_windows_to_single_active(
      &mut windows,
      &mut window_order,
      &mut active_window_id,
      |_| closed += 1,
    );

    assert_eq!(closed, 1);
    assert_eq!(windows.len(), 1);
    assert_eq!(window_order, vec![2u64]);
    assert_eq!(active_window_id, Some(2u64));

    let active_window_index = active_window_id
      .and_then(|id| window_order.iter().position(|other| *other == id))
      .unwrap_or(0)
      .min(window_order.len().saturating_sub(1));
    let session_windows: Vec<BrowserSessionWindow> = window_order
      .iter()
      .filter_map(|id| windows.get(id))
      .map(BrowserSessionWindow::from_app_state)
      .collect();
    let session = fastrender::ui::session::BrowserSession::from_windows(
      session_windows,
      active_window_index,
      AppearanceSettings::default(),
    );

    assert_eq!(session.windows.len(), 1);
    assert_eq!(session.active_window_index, 0);
    assert_eq!(session.windows[0].tabs.len(), 1);
    assert_eq!(
      session.windows[0].tabs[0].url,
      fastrender::ui::about_pages::ABOUT_NEWTAB
    );
    assert_eq!(session.windows[0].show_menu_bar, cfg!(target_os = "macos"));
  }
}

#[cfg(any(test, feature = "browser_ui"))]
const APP_ICON_PNG: &[u8] = include_bytes!("../../assets/app_icon/fastrender.png");

#[cfg(any(test, feature = "browser_ui"))]
#[derive(Debug, Clone)]
struct DecodedRgbaIcon {
  width: u32,
  height: u32,
  rgba: Vec<u8>,
}

#[cfg(any(test, feature = "browser_ui"))]
fn decode_rgba_icon(png_bytes: &[u8]) -> Result<DecodedRgbaIcon, String> {
  let image =
    image::load_from_memory(png_bytes).map_err(|err| format!("image decode error: {err}"))?;
  let rgba = image.to_rgba8();
  let (width, height) = rgba.dimensions();
  let rgba = rgba.into_raw();
  let expected_len = (width as usize)
    .checked_mul(height as usize)
    .and_then(|v| v.checked_mul(4))
    .ok_or_else(|| "icon dimensions overflowed".to_string())?;
  if rgba.len() != expected_len {
    return Err(format!(
      "unexpected RGBA length: got {}, expected {} for {}x{}",
      rgba.len(),
      expected_len,
      width,
      height
    ));
  }
  Ok(DecodedRgbaIcon {
    width,
    height,
    rgba,
  })
}

#[cfg(feature = "browser_ui")]
fn load_window_icon() -> Option<winit::window::Icon> {
  let decoded = match decode_rgba_icon(APP_ICON_PNG) {
    Ok(icon) => icon,
    Err(err) => {
      eprintln!("failed to decode app icon: {err}");
      return None;
    }
  };

  match winit::window::Icon::from_rgba(decoded.rgba, decoded.width, decoded.height) {
    Ok(icon) => Some(icon),
    Err(err) => {
      eprintln!("failed to create winit window icon: {err:?}");
      None
    }
  }
}

#[cfg(feature = "browser_ui")]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum ProfileShortcutAction {
  ToggleBookmarkForActiveTab,
  ToggleHistoryPanel,
  ToggleBookmarksManager,
  ClearHistory,
}

#[cfg(feature = "browser_ui")]
fn profile_shortcut_action(
  modifiers: winit::event::ModifiersState,
  key: winit::event::VirtualKeyCode,
) -> Option<ProfileShortcutAction> {
  // On macOS, prefer Cmd as the "command" modifier. Elsewhere, prefer Ctrl.
  let cmd = if cfg!(target_os = "macos") {
    (modifiers.logo() || modifiers.ctrl()) && !modifiers.alt()
  } else {
    modifiers.ctrl() && !modifiers.alt()
  };

  if cmd && !modifiers.shift() && matches!(key, winit::event::VirtualKeyCode::D) {
    return Some(ProfileShortcutAction::ToggleBookmarkForActiveTab);
  }

  if cmd
    && !modifiers.shift()
    && ((cfg!(target_os = "macos") && matches!(key, winit::event::VirtualKeyCode::Y))
      || (!cfg!(target_os = "macos") && matches!(key, winit::event::VirtualKeyCode::H)))
  {
    return Some(ProfileShortcutAction::ToggleHistoryPanel);
  }

  // Firefox-style history shortcut on macOS.
  if cmd
    && modifiers.shift()
    && cfg!(target_os = "macos")
    && matches!(key, winit::event::VirtualKeyCode::H)
  {
    return Some(ProfileShortcutAction::ToggleHistoryPanel);
  }

  if cmd && modifiers.shift() && matches!(key, winit::event::VirtualKeyCode::O) {
    return Some(ProfileShortcutAction::ToggleBookmarksManager);
  }

  if cmd
    && modifiers.shift()
    && matches!(
      key,
      winit::event::VirtualKeyCode::Delete | winit::event::VirtualKeyCode::Back
    )
  {
    return Some(ProfileShortcutAction::ClearHistory);
  }

  None
}

#[cfg(feature = "browser_ui")]
fn map_page_key_action(
  key: winit::event::VirtualKeyCode,
  modifiers: winit::event::ModifiersState,
) -> Option<fastrender::interaction::KeyAction> {
  use fastrender::interaction::KeyAction;
  use winit::event::VirtualKeyCode;

  // macOS native text-editing parity: Cmd+Left/Right (and shift variants) should behave like
  // Home/End (line start/end). This is important because mac keyboards often don't expose dedicated
  // Home/End keys.
  //
  // Avoid treating Ctrl as a Command equivalent here to preserve Emacs-style Ctrl bindings.
  if cfg!(target_os = "macos") && modifiers.logo() && !modifiers.alt() {
    match key {
      VirtualKeyCode::Left => {
        return Some(if modifiers.shift() {
          KeyAction::ShiftHome
        } else {
          KeyAction::Home
        });
      }
      VirtualKeyCode::Right => {
        return Some(if modifiers.shift() {
          KeyAction::ShiftEnd
        } else {
          KeyAction::End
        });
      }
      _ => {}
    }
  }

  Some(match key {
    VirtualKeyCode::Back => KeyAction::Backspace,
    VirtualKeyCode::Delete => KeyAction::Delete,
    VirtualKeyCode::Return | VirtualKeyCode::NumpadEnter => KeyAction::Enter,
    VirtualKeyCode::Space => {
      if modifiers.shift() {
        KeyAction::ShiftSpace
      } else {
        KeyAction::Space
      }
    }
    VirtualKeyCode::Tab => {
      if modifiers.shift() {
        KeyAction::ShiftTab
      } else {
        KeyAction::Tab
      }
    }
    VirtualKeyCode::Left => {
      if modifiers.shift() {
        KeyAction::ShiftArrowLeft
      } else {
        KeyAction::ArrowLeft
      }
    }
    VirtualKeyCode::Right => {
      if modifiers.shift() {
        KeyAction::ShiftArrowRight
      } else {
        KeyAction::ArrowRight
      }
    }
    VirtualKeyCode::Up => {
      if modifiers.shift() {
        KeyAction::ShiftArrowUp
      } else {
        KeyAction::ArrowUp
      }
    }
    VirtualKeyCode::Down => {
      if modifiers.shift() {
        KeyAction::ShiftArrowDown
      } else {
        KeyAction::ArrowDown
      }
    }
    VirtualKeyCode::PageUp => KeyAction::PageUp,
    VirtualKeyCode::PageDown => KeyAction::PageDown,
    VirtualKeyCode::Home => {
      if modifiers.shift() {
        KeyAction::ShiftHome
      } else {
        KeyAction::Home
      }
    }
    VirtualKeyCode::End => {
      if modifiers.shift() {
        KeyAction::ShiftEnd
      } else {
        KeyAction::End
      }
    }
    _ => return None,
  })
}

