#[cfg(feature = "browser_ui")]
fn rfd_extensions_from_html_accept(accept: Option<&str>) -> Vec<String> {
  let Some(accept) = accept.map(str::trim).filter(|s| !s.is_empty()) else {
    return Vec::new();
  };

  let mut exts: std::collections::BTreeSet<String> = std::collections::BTreeSet::new();

  let mut push_all = |exts: &mut std::collections::BTreeSet<String>, values: &[&str]| {
    for ext in values {
      let ext = ext.trim().trim_start_matches('.');
      if ext.is_empty() {
        continue;
      }
      exts.insert(ext.to_ascii_lowercase());
    }
  };

  for raw_token in accept.split(',') {
    let token = raw_token.trim();
    if token.is_empty() {
      continue;
    }

    let token = token.to_ascii_lowercase();
    if token == "*/*" {
      // Explicitly accept anything; no filter.
      continue;
    }

    if let Some(ext) = token.strip_prefix('.') {
      let ext = ext.trim();
      if ext.is_empty() {
        continue;
      }
      exts.insert(ext.to_string());
      continue;
    }

    match token.as_str() {
      // Wildcard MIME groups.
      "image/*" => push_all(
        &mut exts,
        &[
          "png", "jpg", "jpeg", "gif", "webp", "bmp", "tif", "tiff", "svg",
        ],
      ),
      "text/*" => push_all(
        &mut exts,
        &["txt", "md", "markdown", "csv", "json", "xml", "html", "htm"],
      ),
      "audio/*" => push_all(&mut exts, &["mp3", "wav", "ogg", "flac", "m4a", "aac"]),
      "video/*" => push_all(
        &mut exts,
        &["mp4", "mov", "webm", "mkv", "avi", "mpeg", "mpg"],
      ),

      // Common specific MIME types.
      "image/png" => push_all(&mut exts, &["png"]),
      "image/jpeg" | "image/jpg" => push_all(&mut exts, &["jpg", "jpeg"]),
      "image/gif" => push_all(&mut exts, &["gif"]),
      "image/webp" => push_all(&mut exts, &["webp"]),
      "image/bmp" => push_all(&mut exts, &["bmp"]),
      "image/svg+xml" => push_all(&mut exts, &["svg"]),
      "text/plain" => push_all(&mut exts, &["txt"]),
      "text/markdown" => push_all(&mut exts, &["md", "markdown"]),
      "text/csv" => push_all(&mut exts, &["csv"]),
      "text/html" => push_all(&mut exts, &["html", "htm"]),
      "application/json" => push_all(&mut exts, &["json"]),
      "application/pdf" => push_all(&mut exts, &["pdf"]),
      _ => {}
    }
  }

  exts.into_iter().collect()
}

#[cfg(feature = "browser_ui")]
fn try_native_save_dialog(
  kind: PageExportKind,
  suggested_name: &str,
  default_dir: &std::path::Path,
) -> Option<std::path::PathBuf> {
  let mut dialog = rfd::FileDialog::new().set_file_name(suggested_name);
  if !default_dir.as_os_str().is_empty() {
    dialog = dialog.set_directory(default_dir);
  }

  dialog = match kind {
    PageExportKind::SavePage => dialog.add_filter("HTML file", &["html"]),
    PageExportKind::Print => dialog.add_filter("PNG image", &["png"]),
  };

  dialog.save_file()
}

