#[cfg(any(test, feature = "browser_ui"))]
#[derive(Debug, Clone, Copy, PartialEq)]
enum TouchGestureAction {
  /// A long-press gesture was recognised and should open a page context menu.
  ContextMenu { pos_points: (f32, f32) },
  /// A tap gesture was recognised and should be treated as a primary click.
  Tap { pos_points: (f32, f32) },
}

/// Minimal touch gesture recogniser used to emulate mouse interactions on touch devices.
///
/// This is intentionally self-contained (no winit/egui types) so it can be unit tested without the
/// heavy `browser_ui` feature.
#[cfg(any(test, feature = "browser_ui"))]
#[derive(Debug, Clone)]
struct TouchGestureRecognizer {
  active: Option<ActiveTouchGesture>,
  long_press_threshold: std::time::Duration,
  slop_radius_points: f32,
}

#[cfg(any(test, feature = "browser_ui"))]
#[derive(Debug, Clone)]
struct ActiveTouchGesture {
  id: u64,
  start_pos_points: (f32, f32),
  last_pos_points: (f32, f32),
  start_instant: std::time::Instant,
  long_press_deadline: std::time::Instant,
  moved_too_far: bool,
  long_press_triggered: bool,
}

#[cfg(any(test, feature = "browser_ui"))]
impl TouchGestureRecognizer {
  const DEFAULT_LONG_PRESS_THRESHOLD: std::time::Duration = std::time::Duration::from_millis(500);
  const DEFAULT_SLOP_RADIUS_POINTS: f32 = 8.0;

  fn new() -> Self {
    Self::new_with_config(
      Self::DEFAULT_LONG_PRESS_THRESHOLD,
      Self::DEFAULT_SLOP_RADIUS_POINTS,
    )
  }

  fn new_with_config(long_press_threshold: std::time::Duration, slop_radius_points: f32) -> Self {
    Self {
      active: None,
      long_press_threshold,
      slop_radius_points: slop_radius_points.max(0.0),
    }
  }

  fn reset(&mut self) {
    self.active = None;
  }

  fn next_deadline(&self) -> Option<std::time::Instant> {
    self.active.as_ref().and_then(|gesture| {
      if gesture.moved_too_far || gesture.long_press_triggered {
        None
      } else {
        Some(gesture.long_press_deadline)
      }
    })
  }

  fn touch_start(&mut self, id: u64, now: std::time::Instant, pos_points: (f32, f32)) {
    // Multi-touch is treated as a cancellation of the primary-touch gesture so we don't trigger
    // context menus during pinch/zoom interactions.
    if self.active.is_some() {
      self.active = None;
    }
    self.active = Some(ActiveTouchGesture {
      id,
      start_pos_points: pos_points,
      last_pos_points: pos_points,
      start_instant: now,
      long_press_deadline: now + self.long_press_threshold,
      moved_too_far: false,
      long_press_triggered: false,
    });
  }

  /// Update the active touch gesture with a new position.
  ///
  /// When the gesture transitions into a drag (movement exceeds the configured slop radius), this
  /// returns the most recent finger delta (in egui points) so callers can translate it into a scroll
  /// delta.
  fn touch_move(&mut self, id: u64, pos_points: (f32, f32)) -> Option<(f32, f32)> {
    let Some(active) = self.active.as_mut() else {
      return None;
    };
    if active.id != id {
      return None;
    }

    let prev_pos_points = active.last_pos_points;
    active.last_pos_points = pos_points;
    let delta_points = (
      pos_points.0 - prev_pos_points.0,
      pos_points.1 - prev_pos_points.1,
    );
    if active.long_press_triggered {
      return None;
    }

    if !active.moved_too_far {
      let dx = pos_points.0 - active.start_pos_points.0;
      let dy = pos_points.1 - active.start_pos_points.1;
      let dist2 = dx * dx + dy * dy;
      let max_dist2 = self.slop_radius_points * self.slop_radius_points;
      if dist2 > max_dist2 {
        active.moved_too_far = true;
      }
    }

    if active.moved_too_far && (delta_points.0 != 0.0 || delta_points.1 != 0.0) {
      Some(delta_points)
    } else {
      None
    }
  }

  fn touch_end(
    &mut self,
    id: u64,
    now: std::time::Instant,
    pos_points: (f32, f32),
  ) -> Option<TouchGestureAction> {
    let Some(active) = self.active.take() else {
      return None;
    };
    if active.id != id {
      // Different touch ended; keep the original gesture (best-effort) by restoring it.
      self.active = Some(active);
      return None;
    }

    if active.moved_too_far {
      return None;
    }

    if active.long_press_triggered {
      // Long-press was already emitted via `tick`; do not re-emit on release.
      return None;
    }

    if now >= active.long_press_deadline {
      // Treat a release after the deadline as a long-press even if the periodic tick didn't fire
      // (e.g. event-loop scheduling delays).
      return Some(TouchGestureAction::ContextMenu { pos_points });
    }

    Some(TouchGestureAction::Tap { pos_points })
  }

  fn touch_cancel(&mut self, id: u64) {
    if self.active.as_ref().is_some_and(|active| active.id == id) {
      self.active = None;
    }
  }

  fn tick(&mut self, now: std::time::Instant) -> Option<TouchGestureAction> {
    let Some(active) = self.active.as_mut() else {
      return None;
    };
    if active.moved_too_far || active.long_press_triggered {
      return None;
    }
    if now < active.long_press_deadline {
      return None;
    }

    active.long_press_triggered = true;
    Some(TouchGestureAction::ContextMenu {
      pos_points: active.last_pos_points,
    })
  }
}

#[cfg(feature = "browser_ui")]
#[derive(Debug, Clone, Copy)]
struct WgpuInitOptions {
  backends: wgpu::Backends,
  power_preference: wgpu::PowerPreference,
  force_fallback_adapter: bool,
}

#[cfg(feature = "browser_ui")]
#[derive(Debug)]
struct WorkerWakeHudCounters {
  wake_events_sent: std::sync::atomic::AtomicU64,
  wake_events_coalesced: std::sync::atomic::AtomicU64,
}

#[cfg(feature = "browser_ui")]
impl Default for WorkerWakeHudCounters {
  fn default() -> Self {
    Self {
      wake_events_sent: std::sync::atomic::AtomicU64::new(0),
      wake_events_coalesced: std::sync::atomic::AtomicU64::new(0),
    }
  }
}

#[cfg(feature = "browser_ui")]
#[derive(Debug)]
struct BrowserHud {
  last_frame_start: Option<std::time::Instant>,
  last_frame_cpu_ms: Option<f32>,
  fps: Option<f32>,
  worker_wake_counters: std::sync::Arc<WorkerWakeHudCounters>,
  worker_wake_coalesced_prev: u64,
  worker_wake_sent_prev: u64,
  worker_stats_sample_start: std::time::Instant,
  worker_msgs_since_sample: u64,
  worker_wakes_since_sample: u64,
  worker_empty_wakes_since_sample: u64,
  worker_followup_wakes_since_sample: u64,
  worker_max_drain_since_sample: u64,
  worker_drained_total: u64,
  worker_forwarded_msgs_per_sec: Option<f32>,
  worker_msgs_per_sec: Option<f32>,
  worker_wakes_per_sec: Option<f32>,
  worker_wake_sent_per_sec: Option<f32>,
  worker_followup_wakes_per_sec: Option<f32>,
  worker_empty_wakes_per_sec: Option<f32>,
  worker_coalesced_wakes_per_sec: Option<f32>,
  worker_pending_msgs_estimate: Option<u64>,
  worker_msgs_per_nonempty_wake: Option<f32>,
  worker_last_drain: u64,
  worker_max_drain_recent: u64,
  surface_configure_calls_total: u64,
  page_texture_recreates_total: u64,
  last_upload_ms: f32,
  upload_total_ms: f32,
  last_upload_bytes: u64,
  uploads_this_frame: u32,
  last_upload_textures_updated: u32,
  last_upload_textures_created: u32,
  frame_upload_stats: fastrender::ui::FrameUploadCoalescerStats,
  process_cpu_time_ms_total: Option<u64>,
  process_cpu_percent_recent: Option<f64>,
  process_rss_bytes: Option<u64>,
  /// When set, measure keyboard→present latency for the next present.
  pending_keyboard_input_at: Option<std::time::Instant>,
  /// When set, measure scroll (wheel/scrollbar drag)→present latency for the next present.
  pending_scroll_input_at: Option<std::time::Instant>,
  /// When set, measure resize→present latency for the next present.
  pending_resize_input_at: Option<std::time::Instant>,
  last_keyboard_to_present_ms: Option<u64>,
  last_scroll_to_present_ms: Option<u64>,
  last_resize_to_present_ms: Option<u64>,
  /// Navigation start instants keyed by tab id (used to compute TTFP once the first new frame for
  /// the tab is actually presented).
  nav_ttfp_start: std::collections::HashMap<fastrender::ui::TabId, std::time::Instant>,
  /// Last measured time-to-first-present (TTFP) per tab (ms).
  nav_ttfp_last_ms: std::collections::HashMap<fastrender::ui::TabId, u64>,
  /// Number of pending frame uploads at the start of the last rendered frame.
  pending_frame_uploads_at_frame_start: usize,
  /// Total number of frames dropped/coalesced by `FrameUploadCoalescer` since startup.
  coalesced_frames_total: u64,
  /// Tab id whose page texture was updated during the current frame's `flush_pending_frame_uploads`.
  ///
  /// We record navigation TTFP only when the newly uploaded frame is actually presented.
  page_uploaded_tab_in_frame: Option<fastrender::ui::TabId>,
  text_buf: String,
}

#[cfg(feature = "browser_ui")]
impl BrowserHud {
  fn new() -> Self {
    Self {
      last_frame_start: None,
      last_frame_cpu_ms: None,
      fps: None,
      worker_wake_counters: std::sync::Arc::new(WorkerWakeHudCounters::default()),
      worker_wake_coalesced_prev: 0,
      worker_wake_sent_prev: 0,
      worker_stats_sample_start: std::time::Instant::now(),
      worker_msgs_since_sample: 0,
      worker_wakes_since_sample: 0,
      worker_empty_wakes_since_sample: 0,
      worker_followup_wakes_since_sample: 0,
      worker_max_drain_since_sample: 0,
      worker_drained_total: 0,
      worker_forwarded_msgs_per_sec: None,
      worker_msgs_per_sec: None,
      worker_wakes_per_sec: None,
      worker_wake_sent_per_sec: None,
      worker_followup_wakes_per_sec: None,
      worker_empty_wakes_per_sec: None,
      worker_coalesced_wakes_per_sec: None,
      worker_pending_msgs_estimate: None,
      worker_msgs_per_nonempty_wake: None,
      worker_last_drain: 0,
      worker_max_drain_recent: 0,
      surface_configure_calls_total: 0,
      page_texture_recreates_total: 0,
      last_upload_ms: 0.0,
      upload_total_ms: 0.0,
      last_upload_bytes: 0,
      uploads_this_frame: 0,
      last_upload_textures_updated: 0,
      last_upload_textures_created: 0,
      frame_upload_stats: fastrender::ui::FrameUploadCoalescerStats::default(),
      process_cpu_time_ms_total: None,
      process_cpu_percent_recent: None,
      process_rss_bytes: None,
      pending_keyboard_input_at: None,
      pending_scroll_input_at: None,
      pending_resize_input_at: None,
      last_keyboard_to_present_ms: None,
      last_scroll_to_present_ms: None,
      last_resize_to_present_ms: None,
      nav_ttfp_start: std::collections::HashMap::new(),
      nav_ttfp_last_ms: std::collections::HashMap::new(),
      pending_frame_uploads_at_frame_start: 0,
      coalesced_frames_total: 0,
      page_uploaded_tab_in_frame: None,
      text_buf: String::with_capacity(768),
    }
  }

  fn note_keyboard_input(&mut self, now: std::time::Instant) {
    self.pending_keyboard_input_at = Some(now);
  }

  fn note_scroll_input(&mut self, now: std::time::Instant) {
    self.pending_scroll_input_at = Some(now);
  }

  fn note_resize_input(&mut self, now: std::time::Instant) {
    self.pending_resize_input_at = Some(now);
  }

  fn note_navigation_start(&mut self, tab_id: fastrender::ui::TabId, now: std::time::Instant) {
    self.nav_ttfp_start.insert(tab_id, now);
  }

  fn note_navigation_start_if_absent(
    &mut self,
    tab_id: fastrender::ui::TabId,
    now: std::time::Instant,
  ) {
    self.nav_ttfp_start.entry(tab_id).or_insert(now);
  }

  fn clear_navigation(&mut self, tab_id: fastrender::ui::TabId) {
    self.nav_ttfp_start.remove(&tab_id);
  }

  fn clear_tab(&mut self, tab_id: fastrender::ui::TabId) {
    self.nav_ttfp_start.remove(&tab_id);
    self.nav_ttfp_last_ms.remove(&tab_id);
  }

  fn begin_frame_upload_flush(&mut self, pending_count: usize) {
    self.pending_frame_uploads_at_frame_start = pending_count;
    self.page_uploaded_tab_in_frame = None;
  }

  fn record_page_upload(&mut self, tab_id: fastrender::ui::TabId) {
    self.page_uploaded_tab_in_frame = Some(tab_id);
  }

  fn record_present(
    &mut self,
    now: std::time::Instant,
    active_tab_id: Option<fastrender::ui::TabId>,
  ) {
    if let Some(input_at) = self.pending_keyboard_input_at.take() {
      self.last_keyboard_to_present_ms =
        Some(now.saturating_duration_since(input_at).as_millis() as u64);
    }
    if let Some(input_at) = self.pending_scroll_input_at.take() {
      self.last_scroll_to_present_ms =
        Some(now.saturating_duration_since(input_at).as_millis() as u64);
    }
    // Resize→present latency is meaningful even when we didn't upload a new page pixmap this frame
    // (e.g. egui can scale the existing page texture immediately). Record it on the next present
    // unconditionally.
    if let Some(input_at) = self.pending_resize_input_at.take() {
      self.last_resize_to_present_ms =
        Some(now.saturating_duration_since(input_at).as_millis() as u64);
    }

    let Some(active_tab_id) = active_tab_id else {
      return;
    };

    if self.page_uploaded_tab_in_frame != Some(active_tab_id) {
      return;
    }
    self.page_uploaded_tab_in_frame = None;

    if let Some(start) = self.nav_ttfp_start.remove(&active_tab_id) {
      self.nav_ttfp_last_ms.insert(
        active_tab_id,
        now.saturating_duration_since(start).as_millis() as u64,
      );
    }
  }

  fn record_worker_wake(&mut self, drained_msgs: u64) {
    self.worker_wakes_since_sample = self.worker_wakes_since_sample.saturating_add(1);
    self.worker_msgs_since_sample = self.worker_msgs_since_sample.saturating_add(drained_msgs);
    self.worker_drained_total = self.worker_drained_total.saturating_add(drained_msgs);
    self.worker_last_drain = drained_msgs;
    self.worker_max_drain_since_sample = self.worker_max_drain_since_sample.max(drained_msgs);
    if drained_msgs == 0 {
      self.worker_empty_wakes_since_sample = self.worker_empty_wakes_since_sample.saturating_add(1);
    }
  }

  fn record_worker_followup_wake(&mut self) {
    self.worker_followup_wakes_since_sample =
      self.worker_followup_wakes_since_sample.saturating_add(1);
  }

  fn maybe_sample_worker_rates(&mut self, now: std::time::Instant) {
    let coalesced_total = self
      .worker_wake_counters
      .wake_events_coalesced
      .load(std::sync::atomic::Ordering::Relaxed);
    let sent_total = self
      .worker_wake_counters
      .wake_events_sent
      .load(std::sync::atomic::Ordering::Relaxed);
    let forwarded_total = coalesced_total.saturating_add(sent_total);
    self.worker_pending_msgs_estimate =
      Some(forwarded_total.saturating_sub(self.worker_drained_total));

    const MIN_SAMPLE_INTERVAL: std::time::Duration = std::time::Duration::from_millis(250);
    let dt = now.saturating_duration_since(self.worker_stats_sample_start);
    if dt < MIN_SAMPLE_INTERVAL {
      return;
    }
    let secs = dt.as_secs_f32();
    if !secs.is_finite() || secs <= 0.0 {
      return;
    }

    let msgs = self.worker_msgs_since_sample;
    let wakes = self.worker_wakes_since_sample;
    let empty = self.worker_empty_wakes_since_sample;
    let followup = self.worker_followup_wakes_since_sample;
    let nonempty_wakes = wakes.saturating_sub(empty);
    let coalesced_delta = coalesced_total.saturating_sub(self.worker_wake_coalesced_prev);
    let sent_delta = sent_total.saturating_sub(self.worker_wake_sent_prev);
    let forwarded_delta = coalesced_delta.saturating_add(sent_delta);

    self.worker_forwarded_msgs_per_sec = Some((forwarded_delta as f32 / secs).min(10_000_000.0));
    self.worker_msgs_per_sec = Some((msgs as f32 / secs).min(10_000_000.0));
    self.worker_wakes_per_sec = Some((wakes as f32 / secs).min(10_000_000.0));
    self.worker_wake_sent_per_sec = Some((sent_delta as f32 / secs).min(10_000_000.0));
    self.worker_followup_wakes_per_sec = Some((followup as f32 / secs).min(10_000_000.0));
    self.worker_empty_wakes_per_sec = Some((empty as f32 / secs).min(10_000_000.0));
    self.worker_coalesced_wakes_per_sec = Some((coalesced_delta as f32 / secs).min(10_000_000.0));
    self.worker_msgs_per_nonempty_wake = if nonempty_wakes > 0 {
      Some((msgs as f32 / nonempty_wakes as f32).min(10_000_000.0))
    } else {
      None
    };
    self.worker_max_drain_recent = self.worker_max_drain_since_sample;
    self.worker_wake_coalesced_prev = coalesced_total;
    self.worker_wake_sent_prev = sent_total;

    self.worker_stats_sample_start = now;
    self.worker_msgs_since_sample = 0;
    self.worker_wakes_since_sample = 0;
    self.worker_empty_wakes_since_sample = 0;
    self.worker_followup_wakes_since_sample = 0;
    self.worker_max_drain_since_sample = 0;
  }
}

#[cfg(any(test, feature = "browser_ui"))]
#[derive(Debug, Clone)]
struct WorkerWakePerfLogLine {
  t_ms: u64,
  window_id: String,
  worker_msgs_forwarded_per_sec: f32,
  worker_msgs_processed_per_sec: f32,
  worker_wakes_handled_per_sec: f32,
  worker_wake_events_sent_per_sec: f32,
  worker_wake_events_coalesced_per_sec: f32,
  worker_followup_wakes_per_sec: f32,
  worker_empty_wakes_per_sec: f32,
  worker_pending_msgs_estimate: u64,
  worker_msgs_per_nonempty_wake: Option<f32>,
  worker_last_drain: u64,
  worker_max_drain: u64,
}

#[cfg(any(test, feature = "browser_ui"))]
fn format_worker_wake_perf_log_line(line: &WorkerWakePerfLogLine) -> serde_json::Value {
  serde_json::json!({
    "event": "worker_wake_summary",
    "schema_version": perf_log::SCHEMA_VERSION,
    "t_ms": line.t_ms,
    "window_id": line.window_id.as_str(),
    "worker_msgs_forwarded_per_sec": line.worker_msgs_forwarded_per_sec,
    "worker_msgs_processed_per_sec": line.worker_msgs_processed_per_sec,
    "worker_wakes_handled_per_sec": line.worker_wakes_handled_per_sec,
    "worker_wake_events_sent_per_sec": line.worker_wake_events_sent_per_sec,
    "worker_wake_events_coalesced_per_sec": line.worker_wake_events_coalesced_per_sec,
    "worker_followup_wakes_per_sec": line.worker_followup_wakes_per_sec,
    "worker_empty_wakes_per_sec": line.worker_empty_wakes_per_sec,
    "worker_pending_msgs_estimate": line.worker_pending_msgs_estimate,
    "worker_msgs_per_nonempty_wake": line.worker_msgs_per_nonempty_wake,
    "worker_last_drain": line.worker_last_drain,
    "worker_max_drain": line.worker_max_drain,
  })
}

#[cfg(feature = "browser_ui")]
#[derive(Debug)]
struct WorkerWakePerfLogger {
  window_id: String,
  counters: std::sync::Arc<WorkerWakeHudCounters>,
  perf_log_writer: std::rc::Rc<
    std::cell::RefCell<perf_log::JsonlPerfWriter<std::io::BufWriter<Box<dyn std::io::Write>>>>,
  >,
  start_time: std::time::Instant,
  last_report_at: std::time::Instant,
  next_report_at: std::time::Instant,
  prev_wake_events_sent: u64,
  prev_wake_events_coalesced: u64,
  drained_total: u64,
  drained_since_report: u64,
  wakes_since_report: u64,
  empty_wakes_since_report: u64,
  followup_wakes_since_report: u64,
  last_drain: u64,
  max_drain_since_report: u64,
}

#[cfg(feature = "browser_ui")]
impl WorkerWakePerfLogger {
  const PERF_LOG_INTERVAL: std::time::Duration = std::time::Duration::from_secs(1);

  fn new(
    window_id: winit::window::WindowId,
    counters: std::sync::Arc<WorkerWakeHudCounters>,
    perf_log_writer: std::rc::Rc<
      std::cell::RefCell<perf_log::JsonlPerfWriter<std::io::BufWriter<Box<dyn std::io::Write>>>>,
    >,
  ) -> Self {
    let now = std::time::Instant::now();
    let sent = counters
      .wake_events_sent
      .load(std::sync::atomic::Ordering::Relaxed);
    let coalesced = counters
      .wake_events_coalesced
      .load(std::sync::atomic::Ordering::Relaxed);
    Self {
      window_id: format!("{window_id:?}"),
      counters,
      perf_log_writer,
      start_time: now,
      last_report_at: now,
      next_report_at: now.checked_add(Self::PERF_LOG_INTERVAL).unwrap_or(now),
      prev_wake_events_sent: sent,
      prev_wake_events_coalesced: coalesced,
      drained_total: 0,
      drained_since_report: 0,
      wakes_since_report: 0,
      empty_wakes_since_report: 0,
      followup_wakes_since_report: 0,
      last_drain: 0,
      max_drain_since_report: 0,
    }
  }

  fn record_worker_wake(&mut self, drained_msgs: u64) {
    self.wakes_since_report = self.wakes_since_report.saturating_add(1);
    self.drained_since_report = self.drained_since_report.saturating_add(drained_msgs);
    self.drained_total = self.drained_total.saturating_add(drained_msgs);
    self.last_drain = drained_msgs;
    self.max_drain_since_report = self.max_drain_since_report.max(drained_msgs);
    if drained_msgs == 0 {
      self.empty_wakes_since_report = self.empty_wakes_since_report.saturating_add(1);
    }
  }

  fn record_followup_wake(&mut self) {
    self.followup_wakes_since_report = self.followup_wakes_since_report.saturating_add(1);
  }

  fn drive(&mut self, now: std::time::Instant, control_flow: &mut winit::event_loop::ControlFlow) {
    if now >= self.next_report_at {
      let dt = now.saturating_duration_since(self.last_report_at);
      let secs = dt.as_secs_f32();
      if secs.is_finite() && secs > 0.0 {
        let sent_total = self
          .counters
          .wake_events_sent
          .load(std::sync::atomic::Ordering::Relaxed);
        let coalesced_total = self
          .counters
          .wake_events_coalesced
          .load(std::sync::atomic::Ordering::Relaxed);
        let forwarded_total = sent_total.saturating_add(coalesced_total);
        let sent_delta = sent_total.saturating_sub(self.prev_wake_events_sent);
        let coalesced_delta = coalesced_total.saturating_sub(self.prev_wake_events_coalesced);
        let forwarded_delta = sent_delta.saturating_add(coalesced_delta);

        let wakes = self.wakes_since_report;
        let empty = self.empty_wakes_since_report;
        let followup = self.followup_wakes_since_report;
        let nonempty_wakes = wakes.saturating_sub(empty);
        let msgs = self.drained_since_report;
        let pending_estimate = forwarded_total.saturating_sub(self.drained_total);

        let clamp_rate = |v: f32| {
          if v.is_finite() {
            v.min(10_000_000.0)
          } else {
            0.0
          }
        };
        let forwarded_rate = clamp_rate(forwarded_delta as f32 / secs);
        let msgs_rate = clamp_rate(msgs as f32 / secs);
        let wakes_rate = clamp_rate(wakes as f32 / secs);
        let sent_rate = clamp_rate(sent_delta as f32 / secs);
        let coalesced_rate = clamp_rate(coalesced_delta as f32 / secs);
        let followup_rate = clamp_rate(followup as f32 / secs);
        let empty_rate = clamp_rate(empty as f32 / secs);
        let msgs_per_nonempty_wake = if nonempty_wakes > 0 {
          Some(clamp_rate(msgs as f32 / nonempty_wakes as f32))
        } else {
          None
        };
        let t_ms = now
          .saturating_duration_since(self.start_time)
          .as_millis()
          .min(u128::from(u64::MAX)) as u64;

        let line = WorkerWakePerfLogLine {
          t_ms,
          window_id: self.window_id.clone(),
          worker_msgs_forwarded_per_sec: forwarded_rate,
          worker_msgs_processed_per_sec: msgs_rate,
          worker_wakes_handled_per_sec: wakes_rate,
          worker_wake_events_sent_per_sec: sent_rate,
          worker_wake_events_coalesced_per_sec: coalesced_rate,
          worker_followup_wakes_per_sec: followup_rate,
          worker_empty_wakes_per_sec: empty_rate,
          worker_pending_msgs_estimate: pending_estimate,
          worker_msgs_per_nonempty_wake: msgs_per_nonempty_wake,
          worker_last_drain: self.last_drain,
          worker_max_drain: self.max_drain_since_report,
        };
        let json = format_worker_wake_perf_log_line(&line);
        self.perf_log_writer.borrow_mut().emit_value(&json);

        self.prev_wake_events_sent = sent_total;
        self.prev_wake_events_coalesced = coalesced_total;
        self.last_report_at = now;
        self.drained_since_report = 0;
        self.wakes_since_report = 0;
        self.empty_wakes_since_report = 0;
        self.followup_wakes_since_report = 0;
        self.max_drain_since_report = 0;
      } else {
        self.last_report_at = now;
      }

      self.next_report_at = now.checked_add(Self::PERF_LOG_INTERVAL).unwrap_or(now);
    }

    let deadline = self.next_report_at;
    *control_flow = match *control_flow {
      winit::event_loop::ControlFlow::Wait => winit::event_loop::ControlFlow::WaitUntil(deadline),
      winit::event_loop::ControlFlow::WaitUntil(existing) => {
        winit::event_loop::ControlFlow::WaitUntil(existing.min(deadline))
      }
      other => other,
    };
  }
}

#[cfg(test)]
mod worker_wake_perf_log_format_tests {
  use super::{format_worker_wake_perf_log_line, perf_log, WorkerWakePerfLogLine};

  #[test]
  fn formats_worker_wake_summary_json() {
    let line = WorkerWakePerfLogLine {
      t_ms: 123,
      window_id: "WindowId(42)".to_string(),
      worker_msgs_forwarded_per_sec: 10.0,
      worker_msgs_processed_per_sec: 9.0,
      worker_wakes_handled_per_sec: 2.0,
      worker_wake_events_sent_per_sec: 1.0,
      worker_wake_events_coalesced_per_sec: 99.0,
      worker_followup_wakes_per_sec: 0.5,
      worker_empty_wakes_per_sec: 0.25,
      worker_pending_msgs_estimate: 7,
      worker_msgs_per_nonempty_wake: Some(4.0),
      worker_last_drain: 5,
      worker_max_drain: 9,
    };

    let json = format_worker_wake_perf_log_line(&line);
    assert_eq!(json["event"], "worker_wake_summary");
    assert_eq!(json["schema_version"], perf_log::SCHEMA_VERSION);
    assert_eq!(json["t_ms"], 123);
    assert_eq!(json["window_id"], "WindowId(42)");
    assert_eq!(json["worker_msgs_forwarded_per_sec"], 10.0);
    assert_eq!(json["worker_msgs_processed_per_sec"], 9.0);
    assert_eq!(json["worker_wakes_handled_per_sec"], 2.0);
    assert_eq!(json["worker_wake_events_sent_per_sec"], 1.0);
    assert_eq!(json["worker_wake_events_coalesced_per_sec"], 99.0);
    assert_eq!(json["worker_followup_wakes_per_sec"], 0.5);
    assert_eq!(json["worker_empty_wakes_per_sec"], 0.25);
    assert_eq!(json["worker_pending_msgs_estimate"], 7);
    assert_eq!(json["worker_msgs_per_nonempty_wake"], 4.0);
    assert_eq!(json["worker_last_drain"], 5);
    assert_eq!(json["worker_max_drain"], 9);
  }
}

#[cfg(any(test, feature = "browser_ui"))]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum UiFrameActivity {
  Active,
  Idle,
}

#[cfg(any(test, feature = "browser_ui"))]
fn classify_idle_repaint_frame_activity(
  had_winit_input_since_present: bool,
  had_resize_since_present: bool,
  had_worker_activity_since_present: bool,
  egui_requested_repaint: bool,
) -> UiFrameActivity {
  if had_winit_input_since_present || had_resize_since_present || had_worker_activity_since_present
  {
    UiFrameActivity::Active
  } else {
    // Frames produced solely because egui requested a repaint (or due to event-loop churn) are the
    // core "idle repaint / spin" signal we want to detect, so they should count as idle.
    let _ = egui_requested_repaint;
    UiFrameActivity::Idle
  }
}

#[cfg(feature = "browser_ui")]
#[derive(Debug)]
struct IdleRepaintMonitor {
  /// Whether at least one frame has been presented already.
  ///
  /// "Idle repaint" is defined as activity *since the previous presented frame*, so the first
  /// presented frame is never counted as idle.
  has_presented_once: bool,
  had_winit_input_since_present: bool,
  had_resize_since_present: bool,
  had_worker_activity_since_present: bool,
  /// Whether the previous presented frame's egui output requested a follow-up repaint via
  /// `egui::FullOutput::repaint_after` (i.e. non-`Duration::MAX`).
  had_egui_repaint_request_since_present: bool,

  idle_frames_total: u64,
  idle_frame_times: std::collections::VecDeque<std::time::Instant>,
  idle_frames_per_sec: f32,
  window_id: String,
  last_perf_log: Option<std::time::Instant>,
  perf_log_writer: Option<
    std::rc::Rc<
      std::cell::RefCell<perf_log::JsonlPerfWriter<std::io::BufWriter<Box<dyn std::io::Write>>>>,
    >,
  >,
}

#[cfg(feature = "browser_ui")]
impl IdleRepaintMonitor {
  const IDLE_WINDOW: std::time::Duration = std::time::Duration::from_secs(2);
  const PERF_LOG_INTERVAL: std::time::Duration = std::time::Duration::from_secs(1);

  fn new(
    window_id: winit::window::WindowId,
    perf_log_writer: Option<
      std::rc::Rc<
        std::cell::RefCell<perf_log::JsonlPerfWriter<std::io::BufWriter<Box<dyn std::io::Write>>>>,
      >,
    >,
  ) -> Self {
    Self {
      has_presented_once: false,
      had_winit_input_since_present: false,
      had_resize_since_present: false,
      had_worker_activity_since_present: false,
      had_egui_repaint_request_since_present: false,
      idle_frames_total: 0,
      idle_frame_times: std::collections::VecDeque::new(),
      idle_frames_per_sec: 0.0,
      window_id: format!("{window_id:?}"),
      last_perf_log: None,
      perf_log_writer,
    }
  }

  fn note_winit_event(&mut self, event: &winit::event::WindowEvent<'_>) {
    use winit::event::WindowEvent;

    match event {
      WindowEvent::Resized(_) | WindowEvent::ScaleFactorChanged { .. } => {
        self.had_resize_since_present = true;
      }
      WindowEvent::KeyboardInput { .. }
      | WindowEvent::ReceivedCharacter(_)
      | WindowEvent::Ime(_)
      | WindowEvent::ModifiersChanged(_)
      | WindowEvent::CursorMoved { .. }
      | WindowEvent::CursorEntered { .. }
      | WindowEvent::CursorLeft { .. }
      | WindowEvent::MouseWheel { .. }
      | WindowEvent::MouseInput { .. }
      | WindowEvent::TouchpadMagnify { .. }
      | WindowEvent::TouchpadRotate { .. }
      | WindowEvent::TouchpadPressure { .. }
      | WindowEvent::AxisMotion { .. }
      | WindowEvent::Touch(_) => {
        self.had_winit_input_since_present = true;
      }
      _ => {}
    }
  }

  fn note_worker_activity(&mut self) {
    self.had_worker_activity_since_present = true;
  }

  fn on_frame_presented(&mut self, repaint_after: std::time::Duration) {
    let now = std::time::Instant::now();

    if self.has_presented_once {
      let activity = classify_idle_repaint_frame_activity(
        self.had_winit_input_since_present,
        self.had_resize_since_present,
        self.had_worker_activity_since_present,
        self.had_egui_repaint_request_since_present,
      );
      let is_idle = activity == UiFrameActivity::Idle;

      if is_idle {
        self.idle_frames_total = self.idle_frames_total.saturating_add(1);
        self.idle_frame_times.push_back(now);
      }
    }
    self.has_presented_once = true;

    while let Some(front) = self.idle_frame_times.front() {
      if now.saturating_duration_since(*front) > Self::IDLE_WINDOW {
        self.idle_frame_times.pop_front();
      } else {
        break;
      }
    }

    self.idle_frames_per_sec = if Self::IDLE_WINDOW.as_secs_f32() > 0.0 {
      (self.idle_frame_times.len() as f32) / Self::IDLE_WINDOW.as_secs_f32()
    } else {
      0.0
    };

    if let Some(writer) = self.perf_log_writer.as_ref() {
      let should_log = match self.last_perf_log {
        Some(prev) => now.saturating_duration_since(prev) >= Self::PERF_LOG_INTERVAL,
        None => true,
      };
      if should_log {
        self.last_perf_log = Some(now);
        let mut writer = writer.borrow_mut();
        let t_ms = writer.ms_since_start(now);
        let rolling_window_ms = Self::IDLE_WINDOW.as_millis().min(u128::from(u64::MAX)) as u64;
        let idle_frames_window = u64::try_from(self.idle_frame_times.len()).unwrap_or(u64::MAX);
        writer.emit(&perf_log::PerfEvent::IdleSample {
          schema_version: perf_log::SCHEMA_VERSION,
          t_ms,
          window_id: self.window_id.as_str().into(),
          rolling_window_ms,
          idle_fps: self.idle_frames_per_sec,
          idle_frames_total: self.idle_frames_total,
          idle_frames_window,
        });
      }
    }

    // Reset per-presented-frame activity tracking. `repaint_after` applies to the *next* frame.
    self.had_winit_input_since_present = false;
    self.had_resize_since_present = false;
    self.had_worker_activity_since_present = false;
    self.had_egui_repaint_request_since_present = repaint_after != std::time::Duration::MAX;
  }
}

#[cfg(feature = "browser_ui")]
#[derive(Debug)]
struct ProcessCpuSampler {
  enabled: bool,
  perf_log_writer: Option<
    std::rc::Rc<
      std::cell::RefCell<perf_log::JsonlPerfWriter<std::io::BufWriter<Box<dyn std::io::Write>>>>,
    >,
  >,
  start_cpu_time: Option<std::time::Duration>,
  last_sample_wall: Option<std::time::Instant>,
  last_sample_cpu: Option<std::time::Duration>,
  next_sample_deadline: Option<std::time::Instant>,
  cpu_time_ms_total: Option<u64>,
  cpu_percent_recent: Option<f64>,
}

#[cfg(feature = "browser_ui")]
impl ProcessCpuSampler {
  const SAMPLE_INTERVAL: std::time::Duration = std::time::Duration::from_secs(1);

  fn new(
    perf_log_writer: Option<
      std::rc::Rc<
        std::cell::RefCell<perf_log::JsonlPerfWriter<std::io::BufWriter<Box<dyn std::io::Write>>>>,
      >,
    >,
    hud_enabled: bool,
  ) -> Self {
    let enabled = hud_enabled || perf_log_writer.is_some();
    let now = std::time::Instant::now();

    let mut sampler = Self {
      enabled,
      perf_log_writer,
      start_cpu_time: None,
      last_sample_wall: None,
      last_sample_cpu: None,
      next_sample_deadline: None,
      cpu_time_ms_total: None,
      cpu_percent_recent: None,
    };

    if enabled {
      sampler.prime(now);
    }

    sampler
  }

  fn prime(&mut self, now: std::time::Instant) {
    if let Some(cpu) = fastrender::cpu::current_process_cpu_time() {
      self.start_cpu_time = Some(cpu);
      self.last_sample_wall = Some(now);
      self.last_sample_cpu = Some(cpu);
      self.cpu_time_ms_total = Some(0);
      self.cpu_percent_recent = Some(0.0);
    }
    self.next_sample_deadline = now.checked_add(Self::SAMPLE_INTERVAL);
  }

  fn next_deadline(&self) -> Option<std::time::Instant> {
    if !self.enabled {
      return None;
    }
    self.next_sample_deadline
  }

  fn cpu_time_ms_total(&self) -> Option<u64> {
    self.cpu_time_ms_total
  }

  fn cpu_percent_recent(&self) -> Option<f64> {
    self.cpu_percent_recent
  }

  /// Sample process CPU time if the 1Hz interval has elapsed.
  ///
  /// Returns `true` when metrics were updated (and a `cpu_summary` event may have been emitted).
  fn sample_if_due(&mut self, now: std::time::Instant) -> bool {
    if !self.enabled {
      return false;
    }

    let Some(deadline) = self.next_sample_deadline else {
      return false;
    };
    if now < deadline {
      return false;
    }

    // Schedule the next sample first so a failed sample doesn't cause a tight loop.
    self.next_sample_deadline = now.checked_add(Self::SAMPLE_INTERVAL);

    let Some(current_cpu) = fastrender::cpu::current_process_cpu_time() else {
      // Best-effort: keep old values and try again on the next interval.
      return false;
    };

    let Some(start_cpu) = self.start_cpu_time else {
      // First successful sample: establish a baseline for subsequent deltas.
      self.start_cpu_time = Some(current_cpu);
      self.last_sample_wall = Some(now);
      self.last_sample_cpu = Some(current_cpu);
      self.cpu_time_ms_total = Some(0);
      self.cpu_percent_recent = Some(0.0);
      return true;
    };

    let prev_wall = self.last_sample_wall.unwrap_or(now);
    let prev_cpu = self.last_sample_cpu.unwrap_or(current_cpu);

    let delta_wall = now.saturating_duration_since(prev_wall);
    let delta_cpu = current_cpu.checked_sub(prev_cpu).unwrap_or_default();
    let percent = if delta_wall.is_zero() {
      0.0
    } else {
      (delta_cpu.as_secs_f64() / delta_wall.as_secs_f64()) * 100.0
    };
    let percent = if percent.is_finite() { percent } else { 0.0 };

    let total_cpu = current_cpu.checked_sub(start_cpu).unwrap_or_default();
    let total_ms = u64::try_from(total_cpu.as_millis()).unwrap_or(u64::MAX);

    self.last_sample_wall = Some(now);
    self.last_sample_cpu = Some(current_cpu);
    self.cpu_time_ms_total = Some(total_ms);
    self.cpu_percent_recent = Some(percent);

    if let Some(writer) = self.perf_log_writer.as_ref() {
      let mut writer = writer.borrow_mut();
      let event = perf_log::PerfEvent::CpuSummary {
        schema_version: perf_log::SCHEMA_VERSION,
        ts_ms: writer.ms_since_start(now),
        window_id: "process".into(),
        cpu_time_ms_total: total_ms,
        cpu_percent_recent: percent,
      };
      writer.emit(&event);
    }

    true
  }
}

#[cfg(any(test, feature = "browser_ui"))]
#[derive(Debug, Clone, Copy, Default)]
struct UiFrameBreakdown {
  worker_msgs: std::time::Duration,
  upload: std::time::Duration,
  egui: std::time::Duration,
  tessellate: std::time::Duration,
  wgpu: std::time::Duration,
  present: std::time::Duration,
  total: std::time::Duration,
}

#[cfg(any(test, feature = "browser_ui"))]
impl UiFrameBreakdown {
  fn sum_known(&self) -> std::time::Duration {
    self
      .worker_msgs
      .saturating_add(self.upload)
      .saturating_add(self.egui)
      .saturating_add(self.tessellate)
      .saturating_add(self.wgpu)
      .saturating_add(self.present)
  }

  fn total_ms(&self) -> f64 {
    duration_to_ms(self.total)
  }

  fn sum_known_ms(&self) -> f64 {
    duration_to_ms(self.sum_known())
  }

  fn as_ms(&self) -> perf_log::UiFrameBreakdownMs {
    perf_log::UiFrameBreakdownMs {
      worker_msgs_ms: duration_to_ms(self.worker_msgs),
      upload_ms: duration_to_ms(self.upload),
      egui_ms: duration_to_ms(self.egui),
      tessellate_ms: duration_to_ms(self.tessellate),
      wgpu_ms: duration_to_ms(self.wgpu),
      present_ms: duration_to_ms(self.present),
      total_ms: duration_to_ms(self.total),
    }
  }
}

#[cfg(any(test, feature = "browser_ui"))]
fn duration_to_ms(duration: std::time::Duration) -> f64 {
  sanitize_json_number_f64(duration.as_secs_f64() * 1000.0)
}

#[cfg(feature = "browser_ui")]
#[derive(Debug)]
struct ProcessRssSampler {
  enabled: bool,
  perf_log_writer: Option<
    std::rc::Rc<
      std::cell::RefCell<perf_log::JsonlPerfWriter<std::io::BufWriter<Box<dyn std::io::Write>>>>,
    >,
  >,
  next_sample_deadline: Option<std::time::Instant>,
  rss_bytes: Option<u64>,
}

#[cfg(feature = "browser_ui")]
impl ProcessRssSampler {
  const SAMPLE_INTERVAL: std::time::Duration = std::time::Duration::from_secs(1);

  fn new(
    perf_log_writer: Option<
      std::rc::Rc<
        std::cell::RefCell<
          perf_log::JsonlPerfWriter<std::io::BufWriter<Box<dyn std::io::Write>>>,
        >,
      >,
    >,
    hud_enabled: bool,
  ) -> Self {
    let enabled = hud_enabled || perf_log_writer.is_some();
    let now = std::time::Instant::now();

    let mut sampler = Self {
      enabled,
      perf_log_writer,
      next_sample_deadline: None,
      rss_bytes: None,
    };

    if enabled {
      sampler.prime(now);
    }

    sampler
  }

  fn prime(&mut self, now: std::time::Instant) {
    self.rss_bytes = fastrender::memory::current_rss_bytes();
    self.next_sample_deadline = now.checked_add(Self::SAMPLE_INTERVAL);
  }

  fn next_deadline(&self) -> Option<std::time::Instant> {
    if !self.enabled {
      return None;
    }
    self.next_sample_deadline
  }

  fn rss_bytes(&self) -> Option<u64> {
    self.rss_bytes
  }

  /// Sample process RSS if the 1Hz interval has elapsed.
  ///
  /// Returns `true` when a sample was taken (and a `memory_summary` event may have been emitted).
  fn sample_if_due(&mut self, now: std::time::Instant) -> bool {
    if !self.enabled {
      return false;
    }

    let Some(deadline) = self.next_sample_deadline else {
      return false;
    };
    if now < deadline {
      return false;
    }

    // Schedule the next sample first so a failed sample doesn't cause a tight loop.
    self.next_sample_deadline = now.checked_add(Self::SAMPLE_INTERVAL);

    let rss_bytes = fastrender::memory::current_rss_bytes();
    self.rss_bytes = rss_bytes;

    if let Some(writer) = self.perf_log_writer.as_ref() {
      let rss_mb = rss_bytes.map(fastrender::memory::bytes_to_mb);
      let mut writer = writer.borrow_mut();
      let event = perf_log::PerfEvent::MemorySummary {
        schema_version: perf_log::SCHEMA_VERSION,
        ts_ms: writer.ms_since_start(now),
        window_id: "process".into(),
        rss_bytes,
        rss_mb,
      };
      writer.emit(&event);
    }

    true
  }
}

#[cfg(feature = "browser_ui")]
#[derive(Debug, Default)]
struct TabNotificationUiState {
  warning_toast: fastrender::ui::WarningToastState,
  warning_toast_expanded: bool,
  last_warning_toast: Option<String>,
  last_error: Option<String>,
  error_details_open: bool,
}

#[cfg(feature = "browser_ui")]
impl TabNotificationUiState {
  fn sync_error(&mut self, error: Option<&str>) {
    let error = error.map(str::trim).filter(|s| !s.is_empty());
    if let Some(error) = error {
      let error = error.to_string();
      if Some(&error) != self.last_error.as_ref() {
        self.last_error = Some(error);
        self.error_details_open = false;
      }
    } else {
      // Error no longer present: collapse details, but keep the last message so the infobar can
      // fade out gracefully.
      self.error_details_open = false;
    }
  }
}

#[cfg(feature = "browser_ui")]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum PageTextureFilterPolicy {
  /// Use nearest-neighbour filtering when the page image is drawn at ~1:1, otherwise use linear.
  Auto,
  /// Always use nearest-neighbour filtering for page textures.
  Nearest,
  /// Always use linear filtering for page textures.
  Linear,
}

#[cfg(feature = "browser_ui")]
impl PageTextureFilterPolicy {
  const ENV_KEY: &'static str = "FASTR_BROWSER_PAGE_FILTER";

  fn from_env() -> Self {
    let raw = std::env::var(Self::ENV_KEY).ok();
    let Some(raw) = raw else {
      return Self::Auto;
    };
    let raw = raw.trim();
    if raw.is_empty() {
      return Self::Auto;
    }
    match raw.to_ascii_lowercase().as_str() {
      "auto" => Self::Auto,
      "nearest" => Self::Nearest,
      "linear" => Self::Linear,
      other => {
        eprintln!(
          "{}: invalid value {other:?} (expected nearest|linear|auto); defaulting to auto",
          Self::ENV_KEY
        );
        Self::Auto
      }
    }
  }
}

#[cfg(feature = "browser_ui")]
struct GpuContext {
  instance: wgpu::Instance,
  adapter: wgpu::Adapter,
  device: std::sync::Arc<wgpu::Device>,
  queue: std::sync::Arc<wgpu::Queue>,
}

#[cfg(feature = "browser_ui")]
impl GpuContext {
  async fn new(
    window: &winit::window::Window,
    wgpu_init: WgpuInitOptions,
  ) -> Result<Self, Box<dyn std::error::Error>> {
    let instance = wgpu::Instance::new(wgpu::InstanceDescriptor {
      backends: wgpu_init.backends,
      ..Default::default()
    });
    let surface = unsafe { instance.create_surface(window) }?;

    let adapter_options = wgpu::RequestAdapterOptions {
      power_preference: wgpu_init.power_preference,
      compatible_surface: Some(&surface),
      force_fallback_adapter: wgpu_init.force_fallback_adapter,
    };
    let adapter = instance
      .request_adapter(&adapter_options)
      .await
      .ok_or_else(|| {
        let mut available = Vec::new();
        for adapter in instance.enumerate_adapters(wgpu_init.backends) {
          let info = adapter.get_info();
          available.push(format!("{} ({:?})", info.name, info.backend));
        }
        let available = if available.is_empty() {
          "none".to_string()
        } else {
          available.join(", ")
        };

        let mut msg = format!(
          "wgpu adapter selection failed.\n\
requested: backends={:?} power_preference={:?} force_fallback_adapter={}\n\
available adapters (instance.enumerate_adapters): {available}",
          wgpu_init.backends,
          wgpu_init.power_preference,
          wgpu_init.force_fallback_adapter,
        );

        if !wgpu_init.force_fallback_adapter {
          msg.push_str(&format!(
            "\nHint: Try enabling the software adapter with `--wgpu-fallback` or `{}`=1.",
            fastrender::ui::browser_cli::ENV_WGPU_FALLBACK
          ));
        }

        msg.push_str(&format!(
          "\nHint: Try forcing a backend set with `--wgpu-backends gl` or `{}`=gl.",
          fastrender::ui::browser_cli::ENV_WGPU_BACKENDS
        ));

        msg.push_str(
          "\nHint: If you're running in a headless environment, try `browser --headless-smoke` (skips window + wgpu).",
        );

        std::io::Error::new(std::io::ErrorKind::Other, msg)
      })?;

    let adapter_info = adapter.get_info();
    // Populate `about:gpu` with the adapter selected by the windowed front-end.
    fastrender::ui::about_pages::set_gpu_info(
      adapter_info.name.clone(),
      format!("{:?}", adapter_info.backend),
      format!("{:?}", wgpu_init.power_preference),
      wgpu_init.force_fallback_adapter,
      format!("{:?}", wgpu_init.backends),
    );

    let (device, queue) = adapter
      .request_device(
        &wgpu::DeviceDescriptor {
          label: Some("device"),
          features: wgpu::Features::empty(),
          limits: wgpu::Limits::default(),
        },
        None,
      )
      .await
      .map_err(|err| {
        let mut msg = format!(
          "wgpu device request failed for adapter {adapter_info:?}.\n\
requested: backends={:?} power_preference={:?} force_fallback_adapter={}\n\
error: {err}",
          wgpu_init.backends, wgpu_init.power_preference, wgpu_init.force_fallback_adapter,
        );
        if !wgpu_init.force_fallback_adapter {
          msg.push_str(&format!(
            "\nHint: Try enabling the software adapter with `--wgpu-fallback` or `{}`=1.",
            fastrender::ui::browser_cli::ENV_WGPU_FALLBACK
          ));
        }
        msg.push_str(&format!(
          "\nHint: Try forcing a different backend set with `--wgpu-backends gl` or `{}`=gl.",
          fastrender::ui::browser_cli::ENV_WGPU_BACKENDS
        ));
        std::io::Error::new(std::io::ErrorKind::Other, msg)
      })?;

    Ok(Self {
      instance,
      adapter,
      device: std::sync::Arc::new(device),
      queue: std::sync::Arc::new(queue),
    })
  }
}

