#[cfg(all(test, feature = "browser_ui"))]
mod page_node_accesskit_action_routing_tests {
  use super::{route_page_accesskit_action_request, PageAccesskitActionRoute};
  use fastrender::ui::{encode_page_node_id, TabId, UiToWorker};
  use std::num::NonZeroU128;

  fn node_id_from_u128(raw: u128) -> accesskit::NodeId {
    accesskit::NodeId(NonZeroU128::new(raw).expect("test node id must be non-zero"))
  }

  #[test]
  fn routes_focus_action_request_for_current_page_node() {
    let tab_id = TabId(1);
    let gen = 2u32;
    let dom_node_id = 42usize;
    let target = encode_page_node_id(tab_id, gen, dom_node_id);
    let request = accesskit::ActionRequest {
      target,
      action: accesskit::Action::Focus,
      data: None,
    };

    let route = route_page_accesskit_action_request(&request, Some(tab_id), Some(gen))
      .expect("expected request to be recognized as a page node");
    let msg = match route {
      PageAccesskitActionRoute::Current { msg } => msg,
      other => panic!("expected current route, got {other:?}"),
    };

    match msg {
      Some(UiToWorker::A11ySetFocus {
        tab_id: got_tab,
        node_id: got_node,
      }) => {
        assert_eq!(got_tab, tab_id);
        assert_eq!(got_node, dom_node_id);
      }
      other => panic!("expected A11ySetFocus msg, got {other:?}"),
    }
  }

  #[test]
  fn ignores_stale_generation_page_node_requests() {
    let tab_id = TabId(1);
    let current_gen = 2u32;
    let stale_target = encode_page_node_id(tab_id, current_gen - 1, 1);
    let request = accesskit::ActionRequest {
      target: stale_target,
      action: accesskit::Action::Focus,
      data: None,
    };

    let route = route_page_accesskit_action_request(&request, Some(tab_id), Some(current_gen));
    assert!(
      matches!(route, Some(PageAccesskitActionRoute::Ignored)),
      "expected stale request to be ignored, got {route:?}"
    );
  }

  #[test]
  fn non_page_node_ids_are_not_routed() {
    let tab_id = TabId(1);
    let gen = 1u32;
    let chrome_target = node_id_from_u128(1);
    let request = accesskit::ActionRequest {
      target: chrome_target,
      action: accesskit::Action::Focus,
      data: None,
    };

    let route = route_page_accesskit_action_request(&request, Some(tab_id), Some(gen));
    assert!(route.is_none(), "expected non-page target to return None");
  }
}

#[cfg(all(test, feature = "browser_ui"))]
mod page_host_accesskit_action_tests {
  use super::handle_page_host_accesskit_focus_actions;

  fn run_page_host_frame(
    ctx: &egui::Context,
    page_has_focus: &mut bool,
    chrome: &mut fastrender::ui::ChromeState,
    action_requests: Vec<accesskit::ActionRequest>,
  ) -> egui::FullOutput {
    let mut raw = egui::RawInput::default();
    raw.focused = true;
    raw.pixels_per_point = Some(1.0);
    raw.screen_rect = Some(egui::Rect::from_min_size(
      egui::pos2(0.0, 0.0),
      egui::vec2(320.0, 200.0),
    ));
    raw.events = action_requests
      .into_iter()
      .map(egui::Event::AccessKitActionRequest)
      .collect();

    ctx.begin_frame(raw);
    egui::CentralPanel::default().show(ctx, |ui| {
      let size_points = ui.available_size().max(egui::Vec2::ZERO);
      let response = ui
        .add(egui::Image::new((egui::TextureId::User(0), size_points)).sense(egui::Sense::click()));
      response.widget_info(|| {
        egui::WidgetInfo::labeled(egui::WidgetType::Label, "Web page content (rendered image)")
      });
      let _ = handle_page_host_accesskit_focus_actions(ui, &response, page_has_focus, chrome);
      if *page_has_focus {
        response.request_focus();
      }
    });
    ctx.end_frame()
  }

  fn accesskit_node_id_for_page_host(output: &egui::FullOutput) -> accesskit::NodeId {
    let update =
      output.platform_output.accesskit_update.as_ref().expect(
        "expected AccessKit update to be emitted; ensure ctx.enable_accesskit() was called",
      );

    update
      .nodes
      .iter()
      .find_map(|(id, node)| {
        let name = node.name().unwrap_or("").trim();
        (name == "Web page content (rendered image)").then_some(*id)
      })
      .expect("expected to find page host node in AccessKit update")
  }

  #[test]
  fn accesskit_focus_action_on_page_host_sets_page_focus() {
    let ctx = egui::Context::default();
    ctx.enable_accesskit();

    let mut page_has_focus = false;
    let mut chrome = fastrender::ui::ChromeState::default();
    chrome.address_bar_has_focus = true;
    chrome.request_focus_address_bar = true;
    chrome.request_select_all_address_bar = true;
    chrome.address_bar_editing = true;
    let output = run_page_host_frame(&ctx, &mut page_has_focus, &mut chrome, Vec::new());
    assert!(
      !page_has_focus,
      "expected page to start unfocused before any AccessKit action"
    );

    let node_id = accesskit_node_id_for_page_host(&output);
    let focus_request = accesskit::ActionRequest {
      action: accesskit::Action::Focus,
      target: node_id,
      data: None,
    };

    let _ = run_page_host_frame(&ctx, &mut page_has_focus, &mut chrome, vec![focus_request]);
    assert!(
      page_has_focus,
      "expected AccessKit Focus action on page host to set page_has_focus"
    );
    assert!(
      !chrome.address_bar_has_focus
        && !chrome.request_focus_address_bar
        && !chrome.request_select_all_address_bar
        && !chrome.address_bar_editing,
      "expected chrome focus surfaces to be cleared when the page host receives focus"
    );
  }

  #[test]
  fn accesskit_click_action_on_page_host_sets_page_focus() {
    let ctx = egui::Context::default();
    ctx.enable_accesskit();

    let mut page_has_focus = false;
    let mut chrome = fastrender::ui::ChromeState::default();
    chrome.address_bar_has_focus = true;
    let output = run_page_host_frame(&ctx, &mut page_has_focus, &mut chrome, Vec::new());

    let node_id = accesskit_node_id_for_page_host(&output);
    let click_request = accesskit::ActionRequest {
      action: accesskit::Action::Click,
      target: node_id,
      data: None,
    };

    let _ = run_page_host_frame(&ctx, &mut page_has_focus, &mut chrome, vec![click_request]);
    assert!(
      page_has_focus,
      "expected AccessKit Click action on page host to set page_has_focus"
    );
    assert!(
      !chrome.address_bar_has_focus,
      "expected chrome address bar focus to be cleared"
    );
  }
}

